import type { Question } from "@/domain/types";

/**
 * Banco de questões — alinhado ao ISTQB CTFL Syllabus v4.0.
 * Quantidade por capítulo suficiente para a distribuição do exame (8/6/4/11/9/2)
 * com variação entre execuções. Edite/adicione questões livremente aqui.
 */
export const QUESTIONS: Question[] = [
  // ---------------- Capítulo 1 ----------------
  { id: "c1-01", chapter: 1, prompt: "Qual das opções NÃO é um objetivo típico do teste?", options: [`Encontrar defeitos e falhas presentes no sistema`, `Fornecer informação para apoiar decisões do projeto`, `Provar que o software está totalmente livre de defeitos`, `Prevenir defeitos ao avaliar requisitos e o design`], answerIndex: 2, explanation: `Nenhum teste consegue provar que o software está totalmente livre de defeitos — pelo 1º princípio, o teste mostra a presença de defeitos, mas nunca a sua ausência. Encontrar defeitos, apoiar decisões do projeto e prevenir defeitos avaliando requisitos e design são, esses sim, objetivos válidos.` },
  { id: "c1-02", chapter: 1, prompt: "Uma pessoa comete um engano ao codificar, gerando um problema que, ao ser executado, produz comportamento inesperado. A sequência correta é:", options: ["Falha → defeito → erro", "Erro → defeito → falha", "Defeito → erro → falha", "Erro → falha → defeito"], answerIndex: 1, explanation: `A cadeia causal é: uma pessoa comete um <b>erro</b> (engano), que introduz um <b>defeito</b> no código; quando executado, esse defeito pode provocar uma <b>falha</b> (comportamento inesperado). Por isso a ordem correta é erro → defeito → falha.` },
  { id: "c1-03", chapter: 1, prompt: 'O princípio "teste exaustivo é impossível" implica que a equipe deve:', options: [`Testar absolutamente todas as combinações possíveis de entrada`, `Concentrar esforços usando técnicas, priorização e análise de risco`, `Abrir mão de testar diante da limitação de tempo e recursos`, `Automatizar 100% dos cenários possíveis do sistema`], answerIndex: 1, explanation: `Como testar todas as combinações de entrada é inviável, concentra-se o esforço com <b>técnicas de teste, priorização e análise de risco</b>, testando primeiro o que é mais crítico. Abrir mão de testar ou tentar automatizar 100% não são conclusões do princípio.` },
  { id: "c1-04", chapter: 1, prompt: 'O "agrupamento de defeitos" (defect clustering) estabelece que:', options: [`Os defeitos se distribuem de forma uniforme entre os módulos`, `Poucos módulos costumam conter a maioria dos defeitos`, `Todo defeito presente no sistema resulta em uma falha`, `Defeitos só costumam aparecer no fim do projeto`], answerIndex: 1, explanation: `O <b>agrupamento de defeitos</b> observa que poucos módulos costumam concentrar a maioria dos defeitos. Essa concentração é a base do teste baseado em risco, que direciona mais esforço para essas áreas.` },
  { id: "c1-05", chapter: 1, prompt: 'O "paradoxo do pesticida" indica que:', options: [`Testes automatizados nunca apresentam falhas de execução`, `Repetir os mesmos testes deixa de encontrar novos defeitos`, `Quanto maior o número de defeitos encontrados, melhor o produto`, `Testar cedo no ciclo de vida elimina o teste tardio`], answerIndex: 1, explanation: `O <b>paradoxo do pesticida</b> diz que repetir sempre os mesmos testes deixa de encontrar novos defeitos, pois o sistema fica 'imune' a eles. A solução é revisar e criar novos testes periodicamente.` },
  { id: "c1-06", chapter: 1, prompt: 'A falácia da "ausência de erros" alerta que:', options: [`Corrigir um grande número de defeitos garante o sucesso do produto`, `Um sistema pode ter poucos defeitos e ainda não atender às necessidades dos usuários`, `Nenhum software produzido está livre de defeitos`, `Corrigir um defeito sempre introduz um novo defeito`], answerIndex: 1, explanation: `A <b>falácia da ausência de erros</b> alerta que um sistema pode ter pouquíssimos defeitos e ainda assim ser inútil, se não atender às necessidades e expectativas reais dos usuários. Qualidade não é apenas ausência de defeitos.` },
  { id: "c1-07", chapter: 1, prompt: "Sobre verificação e validação:", options: [`Verificação = produto certo; Validação = feito corretamente (invertido)`, `Verificação = construir corretamente (conforme especificação); Validação = construir o produto certo (atende necessidades)`, `Ambas descrevem exatamente a mesma atividade de teste`, `Validação ocorre exclusivamente após a entrega em produção`], answerIndex: 1, explanation: `<b>Verificação</b> pergunta 'construímos o produto corretamente?' (conforme a especificação); <b>validação</b> pergunta 'construímos o produto certo?' (atende às necessidades). São atividades distintas e complementares.` },
  { id: "c1-08", chapter: 1, prompt: "Qual atividade do processo de teste identifica itens de teste e define condições de teste?", options: [`O planejamento geral do processo de teste`, `Análise de teste`, `A implementação dos casos de teste`, `A execução dos testes já planejados`], answerIndex: 1, explanation: `A <b>análise de teste</b> examina a base de teste para identificar itens de teste e definir as condições de teste — ou seja, decide 'o que testar'. Isso a diferencia do planejamento, da implementação e da execução.` },
  { id: "c1-09", chapter: 1, prompt: "Qual afirmação sobre teste e depuração está correta?", options: [`A depuração é uma atividade que faz parte do teste dinâmico`, `Teste mostra falhas; depuração localiza, analisa e corrige o defeito`, `Depurar significa simplesmente executar os casos de teste`, `Teste e depuração são termos sinônimos na prática`], answerIndex: 1, explanation: `O <b>teste</b> (dinâmico) revela falhas causadas por defeitos; a <b>depuração</b> é a atividade de desenvolvimento que localiza a causa e corrige o defeito. São atividades diferentes, feitas em momentos e papéis distintos.` },
  { id: "c1-10", chapter: 1, prompt: "O viés de confirmação, na psicologia do teste, tende a:", options: [`Ajudar o testador a aceitar informações que contrariam suas crenças`, `Dificultar reconhecer os próprios erros e aceitar informações que contrariam crenças`, `Eliminar completamente a necessidade de independência do teste`, `Melhorar a comunicação entre testadores e desenvolvedores`], answerIndex: 1, explanation: `O <b>viés de confirmação</b> leva a pessoa a favorecer informações que confirmam suas crenças e a resistir às que as contrariam, dificultando reconhecer os próprios erros. É um dos motivos pelos quais a independência de teste agrega valor.` },
  { id: "c1-11", chapter: 1, prompt: "A rastreabilidade entre base de teste e testware serve PRINCIPALMENTE para:", options: [`Substituir completamente a gerência de configuração do projeto`, `Avaliar cobertura, suportar análise de impacto e comunicar progresso aos stakeholders`, `Eliminar a necessidade de definir critérios de saída`, `Garantir que absolutamente todo defeito será encontrado`], answerIndex: 1, explanation: `A <b>rastreabilidade</b> entre base de teste e testware permite avaliar a cobertura, apoiar a análise de impacto de mudanças e comunicar o progresso aos stakeholders. Ela não substitui a gestão de configuração nem garante encontrar todos os defeitos.` },
  { id: "c1-12", chapter: 1, prompt: "Qual é o papel do testador no processo de teste?", options: [`Planejar e monitorar todo o processo de teste`, `Analisar, modelar, implementar e executar testes`, `Decidir sobre a liberação final do produto`, `Gerenciar a equipe e os recursos do projeto`], answerIndex: 1, explanation: `O <b>testador</b> foca as atividades técnicas de analisar, modelar (projetar), implementar e executar os testes. Planejar e monitorar o processo cabe à gerência de teste, e a decisão de liberação é do negócio.` },
  { id: "c1-13", chapter: 1, prompt: "A abordagem de 'equipe completa' (whole-team) no teste afirma que:", options: [`Somente os testadores são responsáveis pela qualidade do produto`, `Qualquer membro com as habilidades necessárias pode testar e todos são responsáveis pela qualidade`, `Desenvolvedores nunca devem participar da execução de testes`, `A independência total da equipe de teste é sempre preferível`], answerIndex: 1, explanation: `Na <b>abordagem de equipe completa</b> (whole-team, da Extreme Programming), qualquer membro com as habilidades necessárias pode testar e todos compartilham a responsabilidade pela qualidade. A qualidade não é responsabilidade exclusiva dos testadores.` },
  { id: "c1-14", chapter: 1, prompt: "Qual é uma desvantagem da independência total de testes (testadores externos)?", options: [`Encontram um número menor de tipos diferentes de defeitos`, `Podem ficar isolados, gerando problemas de comunicação e relação adversa com o dev`, `Nunca questionam as premissas assumidas sobre o sistema`, `São sempre mais lentos na execução do que testadores internos`], answerIndex: 1, explanation: `Um risco da independência total (testadores externos) é o <b>isolamento</b>: podem surgir gargalos de comunicação, perda de colaboração e uma relação adversa com os desenvolvedores. A independência traz benefícios, mas precisa de equilíbrio.` },
  { id: "c1-15", chapter: 1, prompt: "O 'teste antecipado economiza tempo e dinheiro' significa:", options: [`Devemos concentrar todo o teste apenas no início do projeto`, `Defeitos removidos cedo no SDLC não geram artefatos defeituosos posteriores, reduzindo custo da qualidade`, `Testes automatizados são sempre executados mais rapidamente`, `O planejamento de teste deve ocorrer só após o desenvolvimento`], answerIndex: 1, explanation: `Encontrar e remover defeitos <b>cedo</b> evita que artefatos posteriores sejam construídos sobre eles, reduzindo o custo total da qualidade (teste antecipado / shift-left). Isso não significa concentrar todo o teste no início do projeto.` },
  { id: "c1-16", chapter: 1, prompt: "O testware produzido na atividade de IMPLEMENTAÇÃO de teste inclui principalmente:", options: [`Plano de teste e registro de riscos do projeto`, `Condições de teste e casos de teste ainda não priorizados`, `Procedimentos de teste, scripts, conjuntos de teste e dados de teste`, `Relatório de conclusão e lições aprendidas do projeto`], answerIndex: 2, explanation: `A atividade de <b>implementação</b> produz o testware executável: procedimentos e scripts de teste, conjuntos de teste, dados de teste e o cronograma de execução. Condições e casos vêm da análise/projeto; relatórios vêm da conclusão.` },
  { id: "c1-17", chapter: 1, prompt: "Qual princípio de teste está sendo aplicado quando uma equipe decide focar o esforço nos módulos com maior histórico de defeitos?", options: ["Teste exaustivo é impossível", "Teste antecipado economiza tempo", "Agrupamento de defeitos (defect clustering)", "Os testes se degradam (paradoxo do pesticida)"], answerIndex: 2, explanation: `Focar o esforço nos módulos com histórico de mais defeitos é aplicar o princípio do <b>agrupamento de defeitos</b> (defect clustering). Ele orienta o teste baseado em risco para onde os defeitos tendem a se concentrar.` },
  { id: "c1-18", chapter: 1, prompt: "Quais habilidades são particularmente relevantes para testadores?", options: [`Apenas habilidades técnicas avançadas de programação`, `Meticulosidade, atenção a detalhes, comunicação, pensamento analítico e crítico, criatividade`, `Somente o conhecimento profundo do domínio de negócio`, `Apenas a experiência prévia com ferramentas de automação`], answerIndex: 1, explanation: `Testadores precisam de um conjunto amplo de habilidades: meticulosidade e atenção a detalhes, boa comunicação, pensamento analítico e crítico, criatividade — além de conhecimento técnico e de domínio. Competências de programação sozinhas não bastam.` },
  { id: "c1-19", chapter: 1, prompt: `Qual das seguintes declarações é um objetivo válido para os testes?`, options: [`O teste deve começar o mais tarde possível para o desenvolvimento ter tempo suficiente para criar um bom produto`, `Para validar se o objeto de teste funciona como esperado pelos usuários e outras partes interessadas`, `Para provar que todos os possíveis defeitos são identificados`, `Para provar que qualquer defeito remanescente não causará nenhuma falha`], answerIndex: 1, explanation: `Validar se o objeto de teste funciona como esperado pelos usuários e demais stakeholders é um objetivo típico de teste. Provar que todos os defeitos foram achados, ou que os remanescentes não causarão falhas, é impossível.` },
  { id: "c1-20", chapter: 1, prompt: `Qual das seguintes declarações descreve corretamente a diferença entre teste e depuração?`, options: [`Os testes identificam a fonte dos defeitos; a depuração analisa os defeitos e propõe atividades de prevenção`, `Os testes dinâmicos mostram falhas causadas por defeitos; a depuração elimina os defeitos, que são a fonte das falhas`, `Os testes não removem as falhas; mas a depuração remove os defeitos que causam as falhas`, `Os testes dinâmicos previnem as causas das falhas; a depuração remove as falhas`], answerIndex: 1, explanation: `O <b>teste dinâmico</b> mostra falhas causadas por defeitos; a <b>depuração</b> elimina o defeito que é a origem dessas falhas. Essa é a distinção correta entre as duas atividades.` },
  { id: "c1-21", chapter: 1, prompt: `Qual das declarações abaixo descreve a situação mais comum para uma falha descoberta durante os testes ou na produção?`, options: [`O produto falhou quando o usuário selecionou uma opção em uma caixa de diálogo`, `A versão errada de um arquivo de código-fonte compilado foi incluída na compilação`, `O algoritmo de computação utilizou as variáveis de entrada erradas`, `O desenvolvedor interpretou erroneamente a exigência do algoritmo`], answerIndex: 0, explanation: `Uma <b>falha</b> é o comportamento observável incorreto durante o uso — como o produto reagir errado quando o usuário seleciona uma opção. As demais opções descrevem defeitos ou suas causas (erro humano, versão errada), não a falha em si.` },
  { id: "c1-22", chapter: 1, prompt: `O Sr. Test tem testado aplicações de software em dispositivos móveis por um período de 5 anos. Durante vários meses, ele não modificou os casos de teste automatizados existentes e não criou novos casos de teste. Isso leva a que cada vez menos defeitos sejam encontrados através da execução dos testes. Que princípio de teste o Sr. Test não observou?`, options: [`Os testes produzem resultados diferentes conforme o ambiente usado`, `Não é possível cobrir exaustivamente todas as combinações do sistema`, `A repetição dos mesmos testes não encontrará novos defeitos`, `Poucos módulos concentram a maioria dos defeitos do sistema`], answerIndex: 2, explanation: `Ao não atualizar nem criar testes por meses, o Sr. Test caiu no <b>paradoxo do pesticida</b>: os mesmos testes repetidos param de revelar novos defeitos. É preciso revisá-los e variá-los regularmente.` },
  { id: "c1-23", chapter: 1, prompt: `De que forma os testes podem ser parte da Garantia de Qualidade?`, options: [`Ela garante que os requisitos sejam testados`, `Ela fornece aos desenvolvedores uma lista de bugs`, `Ela garante que o código seja testado`, `Ela assegura que os testes sejam suficientes`], answerIndex: 1, explanation: `O teste contribui para a <b>Garantia da Qualidade</b> fornecendo informação sobre defeitos (por exemplo, uma lista de bugs), que alimenta a melhoria do produto e do processo. A GQ é orientada ao processo, e o teste dá visibilidade da qualidade real.` },
  { id: "c1-24", chapter: 1, prompt: `Qual das seguintes atividades faz parte da atividade principal de análise de teste no processo de teste?`, options: [`Identificação de qualquer infraestrutura e ferramentas necessárias`, `Criação de conjuntos de teste a partir de scripts de teste`, `Análise das lições aprendidas para a melhoria do processo`, `Avaliação da base de teste de testabilidade`], answerIndex: 3, explanation: `Avaliar a base de teste quanto à sua <b>testabilidade</b> é uma tarefa central da análise de teste. Identificar ferramentas/infra é planejamento; criar conjuntos a partir de scripts é implementação; lições aprendidas são da conclusão.` },
  { id: "c1-25", chapter: 1, prompt: `Combine os seguintes produtos de trabalho de teste (1-4) com a descrição correta (A-D): 1- Conjunto de teste; 2- Caso de teste; 3- Roteiro de teste; 4- Carta de teste. A- Um conjunto de scripts de teste a serem executados em uma execução de teste específica; B- Um conjunto de instruções para a execução de um teste; C- Contém os resultados esperados; D- Documentação das atividades de teste em testes exploratórios baseados em sessões.`, options: [`1A, 2C, 3B, 4D`, `1D, 2B, 3A, 4C`, `1A, 2C, 3D, 4B`, `1D, 2C, 3B, 4A`], answerIndex: 0, explanation: `Conjunto de teste = scripts agrupados para uma execução específica (A); Caso de teste = contém entradas e resultados esperados (C); Roteiro/procedimento de teste = instruções de execução (B); Carta de teste = documentação de uma sessão exploratória (D). Logo, 1A, 2C, 3B, 4D.` },
  { id: "c1-26", chapter: 1, prompt: `Qual dos itens a seguir fornece a definição do termo caso de teste?`, options: [`Subconjunto do domínio de valor de uma variável dentro de um componente ou sistema no qual todos os valores devem ser tratados da mesma forma com base na especificação.`, `Um conjunto de condições prévias, insumos, ações, resultados esperados e pós-condições, desenvolvido com base em condições de teste.`, `Produtos de trabalho produzidos durante o processo de teste para uso no planejamento, projeto, execução, avaliação e relatórios sobre testes.`, `Uma fonte para determinar um resultado esperado para comparar com o resultado real do sistema em teste.`], answerIndex: 1, explanation: `Um <b>caso de teste</b> é um conjunto de pré-condições, entradas, ações, resultados esperados e pós-condições, desenvolvido a partir de condições de teste — a definição do glossário ISTQB. As outras opções descrevem partição de equivalência, testware e oráculo de teste.` },
  { id: "c1-27", chapter: 1, prompt: `Qual dos seguintes é um objetivo típico dos testes?`, options: [`Encontrar defeitos e falhas.`, `Para validar os trabalhos do plano do projeto, conforme necessário.`, `Garantir testes completos.`, `Comparar os resultados reais com os resultados esperados.`], answerIndex: 0, explanation: `<b>Encontrar defeitos e falhas</b> é um dos objetivos típicos do teste, ao lado de avaliar conformidade, dar confiança e fornecer informação para decisões. 'Comparar resultados reais com esperados' descreve a mecânica de um teste, não o seu objetivo.` },
  { id: "c1-28", chapter: 1, prompt: `Qual dos seguintes é um exemplo de falha em um sistema de controle de velocidade "cruise control" de um carro?`, options: [`O desenvolvedor do sistema esqueceu de renomear variáveis após uma operação de cortar e colar.`, `Código desnecessário que soa um alarme quando a inversão de marcha foi incluída no sistema`, `O sistema deixa de manter uma velocidade definida quando o volume do rádio é aumentado ou diminuído.`, `A especificação do projeto do sistema indica erroneamente as velocidades.`], answerIndex: 2, explanation: `A <b>falha</b> é o comportamento real divergente do esperado durante a execução — o sistema deixar de manter a velocidade ao mexer no rádio. Renomeação esquecida, código extra ou especificação errada são defeitos/causas, não a falha observada.` },
  { id: "c1-29", chapter: 1, prompt: `Qual dos seguintes aspectos é mais um defeito do que uma causa raiz em um rastreador de fitness?`, options: [`Como o autor dos requisitos não estava familiarizado com o domínio do treinamento físico, ele assumiu erroneamente que os usuários queriam batimentos cardíacos em batidas por hora.`, `O testador da interface do smartphone não tinha sido treinado em testes de transição de estado, então falhou em um defeito grave.`, `Uma variável de configuração incorreta implementada para a função GPS poderia causar problemas de localização durante o horário de verão.`, `Como a projetista nunca havia trabalhado em dispositivos que pudessem ser usados, ela entendeu mal os efeitos da luz solar refletida.`], answerIndex: 2, explanation: `A variável de configuração incorreta já implementada é o <b>defeito</b> propriamente dito no artefato. As demais opções descrevem <b>causas-raiz</b> (falta de conhecimento do domínio, falta de treinamento) que levaram a defeitos.` },
  { id: "c1-30", chapter: 1, prompt: `Como resultado da análise de risco, mais testes estão sendo direcionados para aquelas áreas do sistema em teste onde os testes iniciais encontraram mais defeitos do que a média. Qual dos seguintes princípios de teste está sendo aplicado?`, options: [`Cuidado com o paradoxo do pesticida.`, `Os testes são dependentes do contexto.`, `A ausência de erros é uma falácia.`, `Defeitos agrupados.`], answerIndex: 3, explanation: `Direcionar mais testes às áreas onde os testes iniciais já encontraram mais defeitos que a média é aplicar o princípio dos <b>defeitos agrupados</b> (defect clustering). É a lógica central do teste baseado em risco.` },
  { id: "c1-31", chapter: 1, prompt: `Dadas as seguintes atividades e tarefas de teste: (a) Projeto do teste (b) Implementação de testes (c) Execução de testes (d) Conclusão do teste; (1) Entrada de pedidos de alteração para relatórios de defeitos em aberto (2) Identificação de dados de teste para apoiar os casos de teste (3) Priorização de procedimentos de teste e criação de dados de teste (4) Analisar as discrepâncias para determinar sua causa. Qual das seguintes opções MELHOR combina as atividades com as tarefas?`, options: [`A-2, B-3, C-4, D-1`, `A-2, B-1, C-3, D-4`, `A-3, B-2, C-4, D-1`, `A-3, B-2, C-1, D-4`], answerIndex: 0, explanation: `Projeto de teste identifica os dados de teste necessários (2); implementação prioriza procedimentos e cria os dados (3); execução analisa as discrepâncias para achar a causa (4); conclusão registra pedidos de mudança para defeitos ainda abertos (1). Logo, A-2, B-3, C-4, D-1.` },
  { id: "c1-32", chapter: 1, prompt: `Qual das seguintes opções MELHOR descreve como o valor é agregado ao manter a rastreabilidade entre a base de teste e os artefatos de teste?`, options: [`Os testes de manutenção podem ser totalmente automatizados com base em mudanças nas exigências iniciais.`, `É possível determinar se um novo caso de teste aumentou a cobertura das exigências.`, `Os gerentes de testes podem identificar quais testadores encontraram os defeitos de maior gravidade.`, `As áreas que podem ser impactadas por efeitos colaterais de uma mudança podem ser alvo de testes de confirmação.`], answerIndex: 1, explanation: `Manter a <b>rastreabilidade</b> entre base de teste e testware permite avaliar se um novo caso de teste aumentou a cobertura dos requisitos. Também apoia análise de impacto e comunicação, mas o benefício destacado aqui é a medição de cobertura.` },
  { id: "c1-33", chapter: 1, prompt: `Qual das seguintes qualidades é MAIS provável que seja encontrada na mentalidade de um testador e não na de um desenvolvedor?`, options: [`A mentalidade de um testador tende a crescer e amadurecer à medida que o testador ganha experiência.`, `Capacidade de ver o que pode dar errado.`, `Boa comunicação com os membros da equipe.`, `Atenção aos detalhes.`], answerIndex: 1, explanation: `A capacidade de 'ver o que pode dar errado' é própria da <b>mentalidade de teste</b> (curiosidade, ceticismo profissional, atenção ao risco), mais típica de testadores. Atenção a detalhes e boa comunicação são valiosas tanto para testadores quanto para desenvolvedores.` },
  { id: "c1-34", chapter: 1, prompt: `Qual dos seguintes explica MELHOR um benefício dos testes independentes?`, options: [`O uso de uma equipe de teste independente permite que a gerência do projeto atribua a responsabilidade pela qualidade da entrega final à equipe de teste.`, `Quando é possível ter uma equipe de teste externa à organização, há o benefício de essa equipe não ser tão facilmente influenciada pelas pressões de entrega da gerência nem por prazos rígidos.`, `Uma equipe de teste independente pode trabalhar totalmente separada dos desenvolvedores e restringir a comunicação a relatórios de defeitos.`, `Quando as especificações contêm ambiguidades e inconsistências, um testador independente pode ser útil para questionar essas suposições e a interpretação feita pelo desenvolvedor.`], answerIndex: 3, explanation: `Diante de especificações ambíguas ou inconsistentes, um testador independente agrega valor ao <b>questionar as suposições</b> e a interpretação feitas pelo desenvolvedor. Atribuir-lhe a responsabilidade pela qualidade ou restringir a comunicação a relatórios não são benefícios reais da independência.` },

  // ---------------- Capítulo 2 ----------------
  { id: "c2-01", chapter: 2, prompt: '"Para cada atividade de desenvolvimento há uma atividade de teste correspondente" reforça:', options: [`Que o teste só deve começar depois que a codificação termina`, `Que o teste deve começar cedo (shift-left), cada nível com objetivos próprios`, `Que basta realizar apenas o teste de sistema no projeto`, `Que a validação substitui completamente a verificação`], answerIndex: 1, explanation: `A regra 'para cada atividade de desenvolvimento há uma atividade de teste correspondente' apoia o <b>teste antecipado (shift-left)</b>: o teste acompanha cada fase, cada nível com objetivos próprios. Não significa esperar a codificação terminar.` },
  { id: "c2-02", chapter: 2, prompt: "O teste de componente (unitário) foca em:", options: ["Interfaces entre subsistemas distintos do sistema", "Componentes/módulos testados isoladamente", "Requisitos de negócio definidos pelo usuário final", "Todo o sistema integrado de ponta a ponta"], answerIndex: 1, explanation: `O <b>teste de componente (unitário)</b> verifica módulos/classes isoladamente, em geral com mocks/stubs e frameworks de teste. O foco é a lógica interna de cada unidade, não as interfaces entre subsistemas.` },
  { id: "c2-03", chapter: 2, prompt: "O objetivo do teste de integração é avaliar:", options: [`Avaliar apenas a estrutura interna de um único módulo`, `As interfaces e interações entre componentes ou sistemas`, `Avaliar exclusivamente a usabilidade da interface do sistema`, `Avaliar apenas os requisitos não funcionais do sistema`], answerIndex: 1, explanation: `O <b>teste de integração</b> avalia as interfaces e as interações entre componentes ou sistemas — os pontos onde eles se comunicam. Não trata da estrutura interna de um único módulo nem de usabilidade.` },
  { id: "c2-04", chapter: 2, prompt: "Qual é um tipo reconhecido de teste de aceitação?", options: [`Teste de caixa-branca aplicado ao nível de aceitação`, `Teste de aceitação do usuário (UAT)`, `Cobertura de instrução medida durante a aceitação`, `Análise de valor limite aplicada aos dados de entrada`], answerIndex: 1, explanation: `O <b>teste de aceitação do usuário (UAT)</b> é um tipo reconhecido de aceitação, ao lado da aceitação operacional, contratual/regulatória e dos testes alfa/beta. Cobertura de instrução e análise de valor limite são técnicas, não níveis de aceitação.` },
  { id: "c2-05", chapter: 2, prompt: "A diferença entre teste funcional e não funcional é:", options: [`Funcional avalia o desempenho; não funcional avalia as funções (invertido)`, `Funcional = o que o sistema faz; não funcional = quão bem se comporta`, `Ambos avaliam exclusivamente a segurança do sistema`, `O teste não funcional é sempre executado manualmente`], answerIndex: 1, explanation: `O <b>teste funcional</b> avalia o que o sistema faz (suas funções); o <b>não funcional</b> avalia quão bem ele se comporta (desempenho, usabilidade, segurança). São perspectivas complementares.` },
  { id: "c2-06", chapter: 2, prompt: "Teste de confirmação (reteste) e teste de regressão diferem porque:", options: [`São a mesma atividade, apenas com nomes diferentes`, `Confirmação verifica se um defeito foi corrigido; regressão verifica se mudanças não causaram novos defeitos`, `Regressão é feito antes da correção ser aplicada ao sistema`, `Confirmação só usa dados coletados em produção`], answerIndex: 1, explanation: `O <b>teste de confirmação (reteste)</b> reexecuta o caso que falhou para verificar se o defeito foi corrigido; o <b>teste de regressão</b> verifica se as mudanças não quebraram o que já funcionava. São objetivos diferentes.` },
  { id: "c2-07", chapter: 2, prompt: "A análise de impacto é usada principalmente para:", options: [`Escrever o código de correção para os defeitos encontrados`, `Identificar consequências de uma mudança e as áreas afetadas que precisam de regressão`, `Substituir completamente a necessidade de teste de aceitação`, `Estimar o custo de hardware necessário para o novo ambiente`], answerIndex: 1, explanation: `A <b>análise de impacto</b> avalia uma mudança para identificar suas consequências e as áreas afetadas que precisam de regressão. É atividade-chave no teste de manutenção.` },
  { id: "c2-08", chapter: 2, prompt: "O teste alfa e o teste beta diferem porque:", options: [`Alfa é sempre automatizado; beta é sempre executado manualmente`, `Alfa ocorre no ambiente do desenvolvedor; beta ocorre no ambiente do cliente/usuário`, `Beta é realizado antes do teste alfa no cronograma do projeto`, `São idênticos, diferindo apenas no nome dado pela empresa`], answerIndex: 1, explanation: `O <b>teste alfa</b> ocorre no ambiente do desenvolvedor; o <b>teste beta</b> ocorre no ambiente real dos usuários/clientes. Ambos são feitos com usuários e não se distinguem por serem manuais ou automatizados.` },
  { id: "c2-09", chapter: 2, prompt: "No TDD (Desenvolvimento Orientado por Testes), a sequência correta é:", options: [`Implementar o código primeiro, depois escrever os testes e refatorar`, `Escrever testes → implementar o código para satisfazê-los → refatorar`, `Refatorar o código antes mesmo de escrever qualquer teste`, `Implementar, refatorar e só depois pensar em testar`], answerIndex: 1, explanation: `No <b>TDD</b> a sequência é: escrever primeiro o teste (que falha), depois implementar o código mínimo para passar e, por fim, refatorar. O teste guia o desenvolvimento.` },
  { id: "c2-10", chapter: 2, prompt: "Qual é um BENEFÍCIO do DevOps para os testes?", options: [`Elimina por completo a necessidade de qualquer teste manual`, `Feedback rápido sobre qualidade do código e se mudanças afetam negativamente o existente`, `Reduz a necessidade de automatizar os testes de regressão`, `Permite pular completamente o teste de integração`], answerIndex: 1, explanation: `O <b>DevOps</b> traz feedback rápido sobre a qualidade do código e sinaliza cedo se uma mudança prejudicou o que já existia, via CI e automação de regressão. Ele não elimina o teste manual nem o de integração.` },
  { id: "c2-11", chapter: 2, prompt: "A abordagem shift-left no teste refere-se a:", options: [`Mover o teste para o final do ciclo de vida de desenvolvimento`, `Antecipar o teste no ciclo de vida, realizando-o mais cedo no SDLC`, `Testar apenas a interface do usuário do sistema`, `Substituir os testes automatizados por testes manuais`], answerIndex: 1, explanation: `A abordagem <b>shift-left</b> antecipa o teste no ciclo de vida: revisar especificações, escrever testes antes do código, usar CI/CD e análise estática cedo. O objetivo é achar defeitos o quanto antes.` },
  { id: "c2-12", chapter: 2, prompt: "Qual é o propósito das RETROSPECTIVAS no contexto do teste?", options: [`Substituir totalmente o relatório de conclusão do teste`, `Identificar o que funcionou, o que pode melhorar e como incorporar melhorias futuras`, `Revisar apenas o código produzido durante a iteração`, `Definir os critérios de aceite das histórias de usuário`], answerIndex: 1, explanation: `As <b>retrospectivas</b> identificam o que funcionou, o que pode melhorar e como aplicar as melhorias, alimentando a melhoria contínua; os resultados vão para o relatório de conclusão. Não servem só para revisar código nem para definir critérios de aceite.` },
  { id: "c2-13", chapter: 2, prompt: "Qual característica NÃO faz parte da norma ISO/IEC 25010 para teste não funcional?", options: [`Eficiência de desempenho do sistema sob carga`, `Usabilidade percebida pelos usuários finais`, `Portabilidade entre diferentes ambientes operacionais`, `Particionamento de equivalência`], answerIndex: 3, explanation: `<b>Particionamento de equivalência</b> é uma técnica de teste, não uma característica de qualidade. Desempenho, usabilidade e portabilidade, sim, são características da ISO/IEC 25010 usadas em teste não funcional.` },
  { id: "c2-14", chapter: 2, prompt: "Em modelos de desenvolvimento ágil, os testes de regressão são fortes candidatos à automação porque:", options: [`São sempre testes mais simples do que os demais tipos`, `São executados muitas vezes e crescem a cada iteração`, `Exigem uma quantidade muito pequena de dados de teste`, `Só precisam ser executados uma única vez por release`], answerIndex: 1, explanation: `Os testes de <b>regressão</b> são fortes candidatos à automação porque são executados muitas vezes e crescem a cada iteração. Automatizá-los torna viável reexecutá-los com frequência em ambientes ágeis.` },
  { id: "c2-15", chapter: 2, prompt: "Quando ocorre o TESTE DE MANUTENÇÃO por 'aposentadoria' de sistema?", options: [`Quando um novo recurso é adicionado ao sistema em produção`, `Quando o sistema chega ao fim de sua vida útil e precisa ser desativado/arquivado`, `Quando há migração para uma nova linguagem de programação`, `Quando há necessidade de um hot-fix urgente em produção`], answerIndex: 1, explanation: `O teste de manutenção por <b>aposentadoria</b> ocorre quando o sistema chega ao fim da vida útil: testa-se o arquivamento de dados, a restauração e a recuperação. Não se refere a novos recursos, migrações ou hot-fixes.` },
  { id: "c2-16", chapter: 2, prompt: `Como os testes caixa-branca podem ser aplicados durante os testes de aceitação?`, options: [`Para verificar se grandes volumes de dados podem ser transferidos entre sistemas integrados`, `Para verificar se todas as declarações de código e caminhos de decisão de código foram executados`, `Verificar se todos os fluxos do processo de trabalho foram cobertos`, `Para cobrir todas as navegações da página web`], answerIndex: 2, explanation: `Em teste de aceitação, técnicas caixa-branca podem ser usadas para garantir que <b>todos os fluxos de processo de negócio</b> foram percorridos — a 'estrutura' aqui é o fluxo de trabalho, não o código-fonte.` },
  { id: "c2-17", chapter: 2, prompt: `Qual das seguintes declarações comparando testes de componentes e testes de sistemas é VERDADEIRA?`, options: [`O teste de componentes verifica a funcionalidade de módulos de software, objetos de programa e classes que são testados separadamente, enquanto o teste de sistema verifica interfaces entre componentes.`, `Os casos de teste para teste de componentes são geralmente derivados das especificações de componentes, especificações de projeto ou modelos de dados, enquanto os casos de teste para teste de sistemas são geralmente derivados das especificações de requisitos ou casos de uso.`, `O teste de componentes concentra-se apenas nas características funcionais, enquanto o teste de sistemas concentra-se nas características funcionais e não funcionais.`, `Os testes de componentes são de responsabilidade dos testadores, enquanto os testes de sistemas são tipicamente de responsabilidade dos usuários.`], answerIndex: 1, explanation: `Os casos do <b>teste de componente</b> derivam de especificações de componente, de projeto ou modelos de dados; os do <b>teste de sistema</b> derivam de requisitos e casos de uso. Essa é a comparação verdadeira entre os dois níveis.` },
  { id: "c2-18", chapter: 2, prompt: `Qual das seguintes opções é VERDADEIRA sobre teste de regressão e teste de confirmação?`, options: [`O objetivo do teste de regressão é verificar se a correção foi implementada com sucesso, enquanto o objetivo do teste de confirmação é confirmar que a correção não tem efeitos colaterais.`, `O objetivo do teste de regressão é detectar efeitos colaterais não intencionais, enquanto o objetivo do teste de confirmação é verificar se o sistema ainda está funcionando em um novo ambiente.`, `O objetivo do teste de regressão é detectar efeitos colaterais não intencionais, enquanto o objetivo do teste de confirmação é verificar se o defeito original foi corrigido.`, `O objetivo do teste de regressão é verificar se a nova funcionalidade está funcionando, enquanto o objetivo do teste de confirmação é verificar se o defeito original foi corrigido.`], answerIndex: 2, explanation: `<b>Regressão</b>: detectar efeitos colaterais indesejados das mudanças. <b>Confirmação</b>: verificar se o defeito original foi realmente corrigido. As demais alternativas trocam ou confundem esses objetivos.` },
  { id: "c2-19", chapter: 2, prompt: `Qual das seguintes definições é a MELHOR definição de um modelo de desenvolvimento incremental?`, options: [`Definição de requisitos, projeto de software e testes são feitos em fases em que cada parte do sistema é adicionada.`, `Uma fase no processo de desenvolvimento deve começar quando a fase anterior estiver concluída.`, `Os testes são vistos como uma fase separada que ocorre após a conclusão do desenvolvimento.`, `Os testes são adicionados ao desenvolvimento como um incremento.`], answerIndex: 0, explanation: `No <b>desenvolvimento incremental</b>, requisitos, projeto e teste ocorrem em fases nas quais cada parte do sistema é adicionada (incrementos). Não é uma fase sequencial única nem um teste apenas 'adicionado' ao fim.` },
  { id: "c2-20", chapter: 2, prompt: `Qual dos seguintes itens NÃO deve ser um gatilho para testes de manutenção?`, options: [`Decisão de testar a possibilidade de manutenção do software`, `Decisão de testar o sistema após a migração para uma nova plataforma operacional`, `Decisão de testar se os dados arquivados são possíveis de serem recuperados`, `Decisão de testar após "hot fixes"`], answerIndex: 0, explanation: `Testar a <b>manutenibilidade</b> do software é avaliar uma característica de qualidade, não é um gatilho para iniciar o teste de manutenção. Gatilhos reais são migrações, hot-fixes, recuperação de dados arquivados e aposentadoria.` },
  { id: "c2-21", chapter: 2, prompt: `Dadas as seguintes declarações sobre as relações entre as atividades de desenvolvimento de software e as atividades de teste no ciclo de vida de desenvolvimento de software: (1) Cada atividade de desenvolvimento deve ter uma atividade de teste correspondente. (2) A revisão deve começar assim que as versões finais dos documentos estiverem disponíveis. (3) O projeto e a implementação de testes devem começar durante a atividade de desenvolvimento correspondente. (4) As atividades de teste devem começar nos estágios iniciais do ciclo de vida de desenvolvimento de software. Quais dos seguintes CORRETAMENTE mostram quais são verdadeiros e quais são falsos?`, options: [`Verdadeiro - 1, 2; Falso - 3, 4`, `Verdadeiro - 2, 3; Falso - 1, 4`, `Verdadeiro - 1, 2, 4; Falso - 3`, `Verdadeiro - 1, 4; Falso - 2, 3`], answerIndex: 3, explanation: `São verdadeiras: cada atividade de desenvolvimento tem uma atividade de teste correspondente (1) e o teste começa cedo no SDLC (4). São falsas: a revisão só começar com documentos finais (2) — deve ocorrer já em rascunhos — e o projeto/implementação de testes ocorrer apenas durante a atividade de dev correspondente (3), pois o shift-left os antecipa.` },
  { id: "c2-22", chapter: 2, prompt: `Dado que os testes que estão sendo realizados têm os seguintes atributos: - Com base nas especificações da interface - Focado em encontrar falhas na comunicação - A abordagem de teste utiliza tanto tipos de teste funcionais quanto estruturais. Qual dos seguintes níveis de teste é o MAIS provável de ser realizado?`, options: [`Teste de integração`, `Teste de aceitação`, `Teste do sistema`, `Teste de componentes`], answerIndex: 0, explanation: `Testes baseados em interfaces, voltados a achar falhas de comunicação e que combinam abordagens funcionais e estruturais caracterizam o <b>teste de integração</b> — o nível onde os componentes se conectam.` },
  { id: "c2-23", chapter: 2, prompt: `Qual das seguintes declarações sobre tipos e níveis de teste é CORRETA?`, options: [`Os testes funcionais e não funcionais podem ser realizados nos níveis de teste do sistema e de aceitação, enquanto o teste caixa-branca é restrito aos testes de componentes e de integração.`, `Os testes funcionais podem ser realizados em qualquer nível de teste, enquanto o teste caixa-branca é restrito ao teste de componentes.`, `É possível realizar testes funcionais, não-funcionais e caixa-branca em qualquer nível de teste.`, `Os testes funcionais e não funcionais podem ser realizados em qualquer nível de teste, enquanto os testes caixa-branca são restritos aos testes de componentes e integração.`], answerIndex: 2, explanation: `Os tipos de teste (funcional, não funcional, caixa-branca e relacionado a mudanças) podem ser aplicados em <b>qualquer nível de teste</b> — não há restrição de nível. Por isso o caixa-branca não se limita a componente/integração.` },
  { id: "c2-24", chapter: 2, prompt: `Qual das seguintes declarações MELHOR compara os propósitos de teste de confirmação e teste de regressão?`, options: [`O objetivo do teste de regressão é garantir que todos os testes executados anteriormente ainda funcionem corretamente, enquanto o objetivo do teste de confirmação é garantir que reparos não afetaram adversamente outras partes.`, `O objetivo do teste de confirmação é verificar se um defeito previamente encontrado foi corrigido, enquanto o objetivo do teste de regressão é garantir que nenhuma outra parte do sistema foi afetada adversamente pela correção.`, `O objetivo dos testes de regressão é assegurar que mudanças em uma parte do sistema não causem falha em outra parte, enquanto o objetivo dos testes de confirmação é verificar se todos os testes anteriores ainda fornecem os mesmos resultados.`, `O objetivo dos testes de confirmação é confirmar que as mudanças foram feitas com sucesso, enquanto o objetivo dos testes de regressão é executar testes que anteriormente não funcionavam.`], answerIndex: 1, explanation: `Mesma distinção fundamental: o <b>teste de confirmação</b> verifica se um defeito encontrado antes foi corrigido; o <b>teste de regressão</b> garante que a correção não afetou negativamente outras partes do sistema.` },
  { id: "c2-25", chapter: 2, prompt: `Qual das seguintes declarações descreve CORRETAMENTE um papel da análise de impacto nos testes de manutenção?`, options: [`A análise de impacto é utilizada quando se decide se vale a pena uma correção para um sistema mantido.`, `A análise de impacto é utilizada para identificar como os dados devem ser migrados para o sistema mantido.`, `A análise de impacto é utilizada para decidir quais correções quentes são de maior valor para o usuário.`, `A análise de impacto é utilizada para determinar a eficácia de novos casos de teste de manutenção.`], answerIndex: 0, explanation: `A <b>análise de impacto</b> é usada para avaliar se vale a pena aplicar uma correção em um sistema mantido, estimando consequências e custo/benefício da mudança. Não trata de migração de dados nem de priorizar hot-fixes por valor.` },

  // ---------------- Capítulo 3 ----------------
  { id: "c3-01", chapter: 3, prompt: "O teste estático se caracteriza por:", options: [`Executar o código do sistema para observar as falhas geradas`, `Avaliar artefatos sem executar o código (revisões e análise estática)`, `Ser realizado exclusivamente no ambiente de produção`, `Exigir sempre dados de teste preparados dinamicamente`], answerIndex: 1, explanation: `O <b>teste estático</b> avalia artefatos sem executar o código, por meio de revisões (manuais) e análise estática (por ferramenta). Aplica-se a requisitos, código, planos de teste e outros documentos.` },
  { id: "c3-02", chapter: 3, prompt: "Qual é um benefício-chave do teste estático?", options: [`Encontra apenas falhas que ocorrem durante a execução do código`, `Detecta defeitos cedo (mais baratos) e acha problemas que o teste dinâmico dificilmente encontraria`, `Elimina totalmente a necessidade de testes dinâmicos no projeto`, `Só pode ser aplicado quando o código executável já está pronto`], answerIndex: 1, explanation: `O <b>teste estático</b> encontra defeitos cedo — quando corrigi-los é mais barato — e revela problemas que o teste dinâmico dificilmente acharia, como requisitos ambíguos ou código morto. Ele complementa o teste dinâmico, não o substitui.` },
  { id: "c3-03", chapter: 3, prompt: "Do menos ao mais formal, a ordem dos tipos de revisão é:", options: ["Inspeção → técnica → walkthrough → informal", "Informal → walkthrough → revisão técnica → inspeção", "Walkthrough → informal → inspeção → técnica", "Técnica → inspeção → informal → walkthrough"], answerIndex: 1, explanation: `Do menos ao mais formal, a ordem é: <b>informal → walkthrough → revisão técnica → inspeção</b>. A formalidade cresce com o processo definido, os papéis e as métricas coletadas.` },
  { id: "c3-04", chapter: 3, prompt: "Numa inspeção formal, quem lidera a reunião?", options: [`O próprio autor do produto revisado`, `O moderador (facilitador)`, `O gerente responsável pela alocação de recursos`, `O cliente ou patrocinador do projeto`], answerIndex: 1, explanation: `Em uma inspeção formal, quem conduz a reunião é o <b>moderador/facilitador</b>, nunca o autor — isso garante objetividade e foco no processo.` },
  { id: "c3-05", chapter: 3, prompt: "Qual é a função do escriba (scribe) numa revisão?", options: [`Corrigir os defeitos encontrados durante a reunião de revisão`, `Registrar defeitos, decisões e ações da reunião`, `Aprovar formalmente o documento revisado pela equipe`, `Liderar a reunião de revisão e mediar as discussões`], answerIndex: 1, explanation: `O <b>escriba (scribe)</b> registra as anomalias, decisões e ações da reunião de revisão. Não corrige defeitos, não aprova o documento nem lidera a sessão.` },
  { id: "c3-06", chapter: 3, prompt: "O walkthrough é tipicamente liderado por:", options: [`Um moderador completamente independente da equipe`, `O autor do produto de trabalho`, `Um auditor externo contratado especialmente para isso`, `O escriba responsável por registrar as anomalias`], answerIndex: 1, explanation: `O <b>walkthrough</b> é tipicamente conduzido pelo <b>autor</b> do produto de trabalho, que apresenta e explica o material. Difere da inspeção, que é liderada por um moderador.` },
  { id: "c3-07", chapter: 3, prompt: "Um fator de sucesso para revisões é:", options: [`Avaliar o desempenho pessoal do autor do produto revisado`, `Tratar defeitos de forma objetiva, sem culpar o autor`, `Revisar o produto de trabalho sem definir objetivos claros`, `Incluir apenas o autor como participante da revisão`], answerIndex: 1, explanation: `Um fator de sucesso das revisões é tratar os defeitos de forma <b>objetiva</b>, sem culpar o autor — os achados são bem-vindos e focados no produto, não na pessoa. Isso mantém o clima colaborativo.` },
  { id: "c3-08", chapter: 3, prompt: "Qual tipo de defeito é mais facilmente encontrado por teste ESTÁTICO do que por dinâmico?", options: [`Erros de runtime que só aparecem durante a execução real`, `Requisitos ambíguos, código inacessível e desvios de padrão`, `Falhas de desempenho observadas apenas sob carga elevada`, `Erros de integração entre sistemas externos distintos`], answerIndex: 1, explanation: `O teste estático encontra melhor problemas como <b>requisitos ambíguos, código inacessível e desvios de padrão</b> — defeitos difíceis de expor executando o sistema. O dinâmico só revela o que se manifesta em tempo de execução.` },
  { id: "c3-09", chapter: 3, prompt: "Na inspeção formal, o autor NÃO pode assumir qual papel?", options: [`O papel de revisor durante a sessão de revisão`, `Líder da revisão ou relator`, `O papel de participante comum da reunião`, `O papel de responsável pela correção do defeito`], answerIndex: 1, explanation: `Na inspeção, o autor <b>não pode ser líder da revisão nem relator</b>, para preservar a objetividade da avaliação. Ele participa esclarecendo dúvidas, mas não conduz o processo.` },
  { id: "c3-10", chapter: 3, prompt: "O feedback antecipado e frequente dos stakeholders durante o SDLC tem como principal benefício:", options: [`Eliminar por completo a necessidade de testes dinâmicos`, `Evitar mal-entendidos de requisitos, retrabalho dispendioso e prazos perdidos`, `Substituir totalmente as revisões formais do processo`, `Reduzir o número de testadores necessários no projeto`], answerIndex: 1, explanation: `O <b>feedback antecipado e frequente</b> dos stakeholders evita mal-entendidos de requisitos, retrabalho caro e prazos perdidos, permitindo corrigir o rumo cedo. Não substitui revisões formais nem testes dinâmicos.` },
  { id: "c3-11", chapter: 3, prompt: "Qual é a diferença principal entre revisão informal e inspeção?", options: [`Revisões informais nunca conseguem detectar nenhum tipo de defeito`, `Informal não tem processo definido nem resultado documentado; inspeção segue processo completo com métricas`, `As inspeções são sempre lideradas pelo próprio autor do produto`, `Revisões informais são sempre mais eficazes que qualquer inspeção`], answerIndex: 1, explanation: `A <b>revisão informal</b> não tem processo definido nem resultado documentado; a <b>inspeção</b> segue um processo completo, com papéis e métricas. Essa é a principal diferença de formalidade entre elas.` },
  { id: "c3-12", chapter: 3, prompt: "Qual produto de trabalho NÃO é adequado para teste estático?", options: [`Especificação de requisitos ainda em fase de rascunho`, `Código-fonte já implementado pela equipe de desenvolvimento`, `Código executável de terceiros (por restrições legais)`, `Plano de teste elaborado no início do projeto`], answerIndex: 2, explanation: `Código executável de terceiros com <b>restrições legais</b> não pode ser lido/analisado, por isso não é adequado ao teste estático. Requisitos, código-fonte próprio e planos de teste, sim, podem ser revisados.` },
  { id: "c3-13", chapter: 3, prompt: `Quais das seguintes opções são papéis em uma revisão formal?`, options: [`Desenvolvedor, Moderador, Líder de revisão, Revisor, Testador.`, `Autor, Moderador, Gerente, Revisor, Desenvolvedor.`, `Autor, Gerente, Líder de revisão, Revisor, Designer.`, `Autor, Moderador, Líder de revisão, Revisor, Redator.`], answerIndex: 3, explanation: `Os papéis típicos de uma <b>revisão formal</b> são autor, moderador, líder de revisão, revisor e redator (escriba). Papéis como 'gerente' ou 'designer' não integram essa lista padrão.` },
  { id: "c3-14", chapter: 3, prompt: `Quais atividades são realizadas no âmbito do planejamento de uma revisão formal?`, options: [`Coleta de métricas para a avaliação da eficácia da revisão.`, `Responder a quaisquer perguntas que os participantes possam ter.`, `Definição e verificação do cumprimento dos critérios de entrada para a revisão`, `Avaliação dos resultados da revisão em relação aos critérios de saída`], answerIndex: 2, explanation: `No <b>planejamento</b> da revisão define-se e verifica-se o cumprimento dos critérios de entrada, o escopo, os papéis e o cronograma. Coletar métricas e avaliar critérios de saída ocorrem depois, nas atividades finais.` },
  { id: "c3-15", chapter: 3, prompt: `Qual dos tipos de revisão abaixo é a MELHOR opção para escolher quando a revisão deve seguir um processo formal baseado em regras e listas de verificação?`, options: [`Revisão Informal`, `Revisão Técnica`, `Inspeção`, `Walkthrough`], answerIndex: 2, explanation: `A <b>inspeção</b> é o tipo de revisão mais formal, guiada por regras e listas de verificação bem definidas. Por isso é a melhor escolha quando se quer um processo formal e sistemático.` },
  { id: "c3-16", chapter: 3, prompt: `Quais das seguintes afirmações sobre testes estáticos são as mais verdadeiras?`, options: [`Os testes estáticos são uma forma barata de detectar e remover defeitos.`, `Os testes estáticos tornam os testes dinâmicos menos desafiadores`, `Os testes estáticos permitem encontrar problemas de tempo de execução no início do ciclo de vida`, `Ao testar um sistema crítico de segurança, os testes estáticos têm menos valor porque os testes dinâmicos encontram melhor os defeitos.`], answerIndex: 0, explanation: `Como não exige executar o código, o <b>teste estático</b> é uma forma barata de detectar e remover defeitos cedo no ciclo. Ele agrega valor até em sistemas críticos, encontrando defeitos que o dinâmico deixaria passar.` },
  { id: "c3-17", chapter: 3, prompt: `Você foi convidado para uma revisão baseada em checklist de uma descrição do processo de criação de documentos internos. A checklist inclui: I. A pessoa que executa a atividade é claramente identificada? II. Critérios de entrada claramente definidos? III. Critérios de saída claramente definidos? IV. Papéis de apoio claramente definidos? No trecho revisado: "Após verificar a documentação do cliente, o arquiteto do software cria a especificação do sistema. Uma vez concluída, ele convida os testadores e verificadores para a revisão. Uma lista de verificação descreve o escopo. Cada revisor cria comentários — se necessário — e conclui com um comentário oficial." Qual das seguintes declarações sobre sua revisão é correta?`, options: [`O ponto II foi violado porque não está claro qual condição deve ser preenchida para convidar para a revisão.`, `Você percebe que o validador também deveria ser convidado, mas como não faz parte da checklist, não cria um comentário.`, `O ponto III foi violado, pois não está claro o que marca a revisão como concluída.`, `O ponto I foi violado porque não está claro quem está fornecendo a lista de verificação para o convite para a revisão.`], answerIndex: 3, explanation: `O ponto I exige identificar claramente quem executa cada atividade; no trecho não fica claro quem fornece a checklist para o convite à revisão, violando esse critério. Por isso a alternativa sobre o ponto I é a correta.` },
  { id: "c3-18", chapter: 3, prompt: `Qual das seguintes afirmações reflete CORRETAMENTE o valor dos testes estáticos?`, options: [`Ao introduzir revisões, descobrimos que tanto a qualidade das especificações quanto o tempo necessário para o desenvolvimento e os testes aumentaram.`, `Usando testes estáticos significa que temos melhor controle e gerenciamento de defeitos mais barato devido à facilidade de detecção de defeitos mais tarde no ciclo de vida.`, `Agora que exigimos o uso de análise estática, as exigências não atendidas diminuíram e a comunicação entre testadores e desenvolvedores melhorou.`, `Desde que começamos a usar análise estática, encontramos defeitos de codificação que podem não ter sido encontrados realizando apenas testes dinâmicos.`], answerIndex: 3, explanation: `Um valor concreto do teste estático é revelar <b>defeitos de codificação</b> que testes dinâmicos sozinhos poderiam não encontrar. Ele melhora a qualidade sem depender da execução do sistema.` },
  { id: "c3-19", chapter: 3, prompt: `Qual das seguintes declarações sobre o uso de listas de verificação em uma revisão formal é CORRETA?`, options: [`Como parte do planejamento da revisão, os revisores criam as listas de verificação necessárias para a revisão.`, `Como parte da comunicação da questão, os revisores preenchem as listas de verificação previstas para a revisão.`, `Como parte da reunião de revisão, os revisores criam relatórios de defeitos com base nas listas de verificação previstas para a revisão.`, `Como parte do início da revisão, os revisores recebem as listas de verificação necessárias para a revisão.`], answerIndex: 3, explanation: `As listas de verificação são entregues aos revisores na atividade de <b>início da revisão (kick-off)</b>, e não criadas por eles durante a reunião. Isso prepara todos para revisar com os mesmos critérios.` },
  { id: "c3-20", chapter: 3, prompt: `Qual das seguintes funções e responsabilidades se encaixa CORRETAMENTE em uma revisão formal?`, options: [`Gerente - Decide sobre a execução das revisões`, `Líder de revisão - Assegura o funcionamento eficaz das reuniões de revisão`, `Escriba - Corrige defeitos no produto de trabalho em revisão`, `Moderador - Monitora a relação custo-benefício contínua`], answerIndex: 0, explanation: `O <b>gerente</b> decide sobre a realização das revisões e aloca tempo e recursos no cronograma. Corrigir defeitos, garantir a eficácia da reunião e monitorar custo/benefício são responsabilidades de outros papéis.` },
  { id: "c3-21", chapter: 3, prompt: `As revisões utilizadas em sua organização têm os seguintes atributos: há um papel de escriba; o objetivo é detectar defeitos potenciais; a reunião é liderada pelo autor; os revisores encontram defeitos potenciais por revisão individual; é produzido um relatório de revisão. Qual dos seguintes tipos de revisão é o MAIS provável que seja utilizado?`, options: [`Revisão Informal`, `Walkthrough`, `Revisão Técnica`, `Inspeção`], answerIndex: 2, explanation: `Papel de escriba, foco em detectar defeitos, reunião conduzida pelo autor, preparação individual e produção de relatório caracterizam a <b>revisão técnica</b>. A inspeção seria conduzida por um moderador.` },
  { id: "c3-22", chapter: 3, prompt: `Você foi convidado a participar de uma revisão baseada em checklist da especificação de requisitos de um sistema de biblioteca, com a tarefa de identificar inconsistências entre requisitos individuais. Entre os requisitos: (6) obter respostas do sistema em 5 segundos (bibliotecários); (9) mutuário multado por não devolver livro em 3 semanas; (10) mutuário obter respostas do sistema em 3 segundos; (11) mutuário pode emprestar um livro sem custo por até 4 semanas; (15) o sistema deve responder a todos os usuários em 3 segundos. Qual dos seguintes CORRETAMENTE identifica inconsistências entre pares de requisitos?`, options: [`6-10, 6-15, 7-12`, `6-15, 9-11`, `6-10, 6-15, 9-11`, `6-15, 7-12`], answerIndex: 1, explanation: `O requisito 6 (5s para bibliotecários) conflita com o requisito geral 15 (3s para todos os usuários); e o requisito 9 (multa após 3 semanas) conflita com o 11 (empréstimo grátis por até 4 semanas). Por isso as inconsistências são 6-15 e 9-11.` },

  // ---------------- Capítulo 4 ----------------
  { id: "c4-01", chapter: 4, prompt: "Um campo aceita idades de 18 a 65. No particionamento de equivalência, quantas partições existem?", options: ["1", "2", "3", "4"], answerIndex: 2, explanation: `O intervalo 18–65 gera <b>3 partições</b>: inválida abaixo (<18), válida (18–65) e inválida acima (>65). Cada partição inteira é representada por um único valor de teste.` },
  { id: "c4-02", chapter: 4, prompt: "Para o intervalo 18–65, quais valores a análise de valor limite (2 valores) sugere?", options: ["Só 18 e 65", "17, 18, 65 e 66", "0 e 100", "18, 40 e 65"], answerIndex: 1, explanation: `A <b>BVA de 2 valores</b> testa cada limite e o seu vizinho imediato: no intervalo 18–65, isso dá 17 e 18 (limite inferior) e 65 e 66 (limite superior).` },
  { id: "c4-03", chapter: 4, prompt: "A tabela de decisão é especialmente útil quando:", options: [`Quando existe apenas uma entrada simples e uma única saída`, `Combinações de condições levam a diferentes ações/regras`, `Quando o objetivo é apenas medir a cobertura de código alcançada`, `Quando o sistema não possui nenhuma regra de negócio definida`], answerIndex: 1, explanation: `A <b>tabela de decisão</b> é ideal quando combinações de condições levam a diferentes ações/regras, como em regras de negócio. Ela força a considerar sistematicamente cada combinação relevante.` },
  { id: "c4-04", chapter: 4, prompt: "O teste de transição de estado modela o sistema em termos de:", options: [`Apenas as instruções e os desvios de fluxo do código`, `Estados, eventos, transições e ações`, `Somente as partições de entrada, sem considerar sequência`, `Apenas os riscos identificados para o projeto`], answerIndex: 1, explanation: `O <b>teste de transição de estado</b> modela o sistema em termos de estados, eventos, transições e ações. É útil quando o comportamento depende do estado atual (do histórico).` },
  { id: "c4-05", chapter: 4, prompt: "A cobertura de instruções (statement) mede:", options: [`A porcentagem de decisões do código exercitadas pelos testes`, `% de instruções executáveis exercitadas`, `O número de defeitos encontrados por módulo testado`, `A porcentagem de requisitos cobertos pelos testes`], answerIndex: 1, explanation: `A <b>cobertura de instruções (statement)</b> mede o percentual de comandos executáveis do código efetivamente executados pelos testes. Não mede decisões, requisitos nem defeitos por módulo.` },
  { id: "c4-06", chapter: 4, prompt: "Sobre cobertura de decisão e de instrução:", options: [`100% de instrução garante 100% de decisão (relação invertida)`, `100% de decisão garante 100% de instrução, mas não o inverso`, `As duas coberturas são sempre matematicamente equivalentes`, `Nenhuma das coberturas garante ou implica a outra`], answerIndex: 1, explanation: `A cobertura de <b>decisão é mais forte</b> que a de instrução: atingir 100% de decisão garante 100% de instrução, mas o inverso não é verdadeiro. Executar todas as decisões implica executar todas as instruções envolvidas.` },
  { id: "c4-07", chapter: 4, prompt: "Qual técnica é baseada em experiência?", options: [`Particionamento de equivalência dos dados de entrada`, `Suposição de erro (error guessing)`, `Tabela de decisão para combinações de condições`, `Análise de valor limite dos dados de entrada`], answerIndex: 1, explanation: `A <b>suposição de erro (error guessing)</b> é uma técnica baseada em experiência, assim como o teste exploratório e o baseado em checklist. Partição de equivalência, BVA e tabela de decisão são técnicas caixa-preta.` },
  { id: "c4-08", chapter: 4, prompt: "No ATDD, os casos de teste são:", options: [`Escritos somente após a entrega do incremento ao cliente`, `Derivados colaborativamente dos critérios de aceitação, antes de codificar`, `Gerados automaticamente pela ferramenta de gestão de testes`, `Ignorados até a fase de manutenção do sistema`], answerIndex: 1, explanation: `No <b>ATDD</b>, os casos de teste são derivados colaborativamente dos critérios de aceitação, antes de codificar, e orientam o desenvolvimento. Não são gerados automaticamente nem deixados para a manutenção.` },
  { id: "c4-09", chapter: 4, prompt: "O teste exploratório caracteriza-se por:", options: [`Seguir roteiros de teste detalhados definidos previamente`, `Projeto e execução simultâneos, com aprendizado sobre o sistema`, `Ausência total de objetivos durante a sessão de teste`, `Ser sempre automatizado por uma ferramenta de execução`], answerIndex: 1, explanation: `O <b>teste exploratório</b> combina projeto, execução e aprendizado de forma simultânea, guiado por cartas de teste (test charters). Não segue roteiros detalhados definidos previamente.` },
  { id: "c4-10", chapter: 4, prompt: "O particionamento de equivalência baseia-se na ideia de que:", options: [`Todo valor possível do domínio de entrada deve ser testado`, `Valores de uma mesma partição são processados da mesma forma, bastando 1 representante`, `Somente os valores inválidos de cada partição são relevantes`, `Os valores nos limites de uma partição nunca causam falhas`], answerIndex: 1, explanation: `O <b>particionamento de equivalência</b> parte da ideia de que todos os valores de uma mesma partição são tratados do mesmo modo, bastando 1 representante para cobri-la. Aplica-se a partições válidas e inválidas.` },
  { id: "c4-11", chapter: 4, prompt: "A técnica baseada em checklist consiste em:", options: [`Gerar entradas de teste de forma totalmente aleatória`, `Verificar itens de uma lista pré-definida de condições a checar`, `Medir a cobertura de ramos exercitados pelos testes`, `Escrever uma tabela de decisão com todas as combinações`], answerIndex: 1, explanation: `A técnica <b>baseada em checklist</b> verifica itens de uma lista pré-definida de condições, derivada de experiência, padrões ou riscos. É baseada em experiência, e não uma medida de cobertura estrutural.` },
  { id: "c4-12", chapter: 4, prompt: "Qual é a diferença entre caixa-preta e caixa-branca?", options: [`Caixa-preta usa o código-fonte; caixa-branca usa a especificação (invertido)`, `Caixa-preta baseia-se no comportamento/especificação; caixa-branca, na estrutura interna/código`, `São termos sinônimos usados por diferentes autores`, `Caixa-branca só pode ser executada de forma manual`], answerIndex: 1, explanation: `O <b>caixa-preta</b> deriva testes do comportamento/especificação, sem olhar o código; o <b>caixa-branca</b> baseia-se na estrutura interna/código. São perspectivas diferentes, não sinônimos.` },
  { id: "c4-13", chapter: 4, prompt: "Um programa tem 10 instruções; os testes executam 7. A cobertura de instruções é:", options: ["100%", "70%", "7%", "Não é possível calcular"], answerIndex: 1, explanation: `Se 7 de 10 instruções são executadas, a cobertura de instruções é 7/10 = <b>70%</b>. A métrica é sempre a proporção de instruções executáveis exercitadas.` },
  { id: "c4-14", chapter: 4, prompt: "Para a BVA de 3 valores aplicada ao intervalo 18–65, quais são os valores de teste corretos?", options: ["17, 18, 65, 66", "17, 18, 19, 64, 65, 66", "18, 65", "16, 17, 18, 65, 66, 67"], answerIndex: 1, explanation: `A <b>BVA de 3 valores</b> testa cada limite mais os dois vizinhos: no intervalo 18–65, isso dá 17, 18, 19 (limite inferior) e 64, 65, 66 (limite superior).` },
  { id: "c4-15", chapter: 4, prompt: "A diferença entre BVA de 2 valores e BVA de 3 valores é:", options: [`BVA de 2 valores é sempre mais rigorosa que a de 3 valores`, `BVA 3 valores é mais rigorosa e pode detectar defeitos que BVA 2 valores perderia`, `As duas variantes têm exatamente o mesmo nível de rigor`, `BVA de 3 valores só pode ser aplicada a partições inválidas`], answerIndex: 1, explanation: `A <b>BVA de 3 valores</b> é mais rigorosa: ao incluir os dois vizinhos de cada limite, detecta defeitos que a de 2 valores perderia (por exemplo, um '=' usado no lugar de '≤'). As duas não têm o mesmo rigor.` },
  { id: "c4-16", chapter: 4, prompt: "Na tabela de decisão, o símbolo '-' (traço) em uma condição significa:", options: [`A condição é sempre avaliada como falsa nessa regra`, `O valor da condição é irrelevante para o resultado daquela regra`, `A condição representa uma combinação tecnicamente inviável`, `A ação correspondente nunca é executada nessa regra`], answerIndex: 1, explanation: `Na tabela de decisão, o traço '-' indica que o valor daquela condição é <b>irrelevante</b> para o resultado da regra — ela não afeta a ação naquela coluna. Não significa 'falso' nem combinação inviável.` },
  { id: "c4-17", chapter: 4, prompt: "A cobertura de 'todos os estados' na transição de estado é considerada:", options: [`A mais rigorosa entre todas as coberturas de transição de estado`, `A mais fraca — pode ser obtida sem executar todas as transições`, `Exatamente equivalente à cobertura de transições válidas`, `Adequada como único critério para sistemas de missão crítica`], answerIndex: 1, explanation: `A cobertura de <b>todos os estados</b> é a mais fraca da transição de estado: pode ser alcançada sem exercitar todas as transições. Não equivale à cobertura de transições nem basta para sistemas críticos.` },
  { id: "c4-18", chapter: 4, prompt: "A sigla INVEST para histórias de usuário significa:", options: ["Independente, Negociável, Valioso, Estimável, Small, Testável", "Integrado, Numérico, Válido, Explícito, Simples, Técnico", "Incremental, Necessário, Verificável, Eficiente, Seguro, Tangível", "Identificável, Novo, Versátil, Escalável, Simples, Testado"], answerIndex: 0, explanation: `<b>INVEST</b> resume os critérios de qualidade de uma boa história de usuário: Independente, Negociável, Valiosa, Estimável, Small (pequena) e Testável.` },
  { id: "c4-19", chapter: 4, prompt: "Um ponto fraco das técnicas caixa-branca é:", options: [`Não considera em nenhum momento o código-fonte do sistema`, `Se o software não implementou um requisito, a ausência pode não ser detectada`, `Só pode ser usada no nível de teste de sistema`, `Não fornece nenhuma medição objetiva de cobertura alcançada`], answerIndex: 1, explanation: `Um ponto fraco do caixa-branca é que ele testa apenas o que foi implementado — se um <b>requisito não foi implementado</b>, essa ausência pode passar despercebida. Achar requisitos faltantes é força do caixa-preta.` },
  { id: "c4-20", chapter: 4, prompt: "No ATDD, após os casos de teste positivos serem criados, a equipe deve:", options: [`Encerrar definitivamente a criação de casos de teste`, `Criar testes negativos e depois cobrir características não funcionais`, `Iniciar imediatamente a implementação do código`, `Aguardar a validação de todos os casos positivos pelo cliente`], answerIndex: 1, explanation: `No <b>ATDD</b>, após criar os casos positivos, a equipe cria os casos negativos e depois cobre características não funcionais. A ordem é: positivos → negativos → não funcionais.` },
  { id: "c4-21", chapter: 4, prompt: "Os 'ataques a falhas' (fault attacks) são uma abordagem metódica de qual técnica?", options: [`Particionamento de equivalência dos dados de entrada`, `Suposição de erro (error guessing)`, `Análise de valor limite aplicada aos dados de entrada`, `Teste exploratório guiado por cartas de teste`], answerIndex: 1, explanation: `Os <b>ataques a falhas (fault attacks)</b> são a forma metódica da suposição de erro: uma lista sistemática de prováveis erros, defeitos e falhas a provocar. É, portanto, uma técnica baseada em experiência.` },
  { id: "c4-22", chapter: 4, prompt: `Qual das seguintes respostas descreve uma condição de teste?`, options: [`Uma característica distinta de um componente ou sistema`, `Um aspecto testável de um componente ou sistema identificado como base para os testes`, `O grau em que um produto de software fornece funções que atendem às necessidades declaradas e implícitas quando o software é utilizado sob condições específicas`, `Casos de teste projetados para executar combinações de condições e ações resultantes delas`], answerIndex: 1, explanation: `Uma <b>condição de teste</b> é um aspecto testável de um componente ou sistema, identificado como base para os testes. As outras opções definem característica de qualidade, testware e caso de teste.` },
  { id: "c4-23", chapter: 4, prompt: `Qual das seguintes opções é classificada como uma técnica de teste caixa-preta?`, options: [`Uma técnica baseada na análise da arquitetura`, `Uma técnica que verifica se o objeto de teste está funcionando de acordo com o projeto detalhado`, `Uma técnica baseada no conhecimento de falhas do passado, ou conhecimento geral de falhas`, `Uma técnica baseada em requisitos formais`], answerIndex: 3, explanation: `Técnicas <b>caixa-preta</b> derivam os testes de especificações/requisitos formais, sem considerar a estrutura interna do código. Basear-se na arquitetura ou no projeto detalhado seria caixa-branca.` },
  { id: "c4-24", chapter: 4, prompt: `A seguinte declaração se refere à cobertura de decisões: "Quando o código contém apenas uma única declaração 'se' e sem loops ou declarações CASE, e sua execução não está aninhada dentro do teste, qualquer caso de teste único que executarmos resultará em 50% de cobertura de decisão". Qual das seguintes afirmações é correta?`, options: [`A declaração é verdadeira. Qualquer caso de teste único fornece 100% de cobertura de decisão e, portanto, 50% de cobertura de decisão.`, `A afirmação é verdadeira. Qualquer caso isolado de teste faria com que o resultado da declaração "se" fosse verdadeiro ou falso.`, `A afirmação é falsa. Um único caso de teste só pode garantir uma cobertura de decisão de 25% neste caso.`, `A afirmação é falsa. A declaração é muito ampla. Ela pode estar correta ou não, dependendo do software testado.`], answerIndex: 1, explanation: `Com um único 'se', sem laços ou aninhamento, cada caso de teste exercita apenas um dos dois desfechos possíveis (verdadeiro ou falso), atingindo 50% de cobertura de decisão. Seriam necessários dois casos para chegar a 100%.` },
  { id: "c4-25", chapter: 4, prompt: `Qual das seguintes é a descrição da cobertura das declarações?`, options: [`É uma métrica, que é a porcentagem de casos de teste que foram executados`, `É uma métrica, que é a porcentagem de declarações no código fonte que foram executadas`, `É uma métrica, que é o número de declarações no código fonte que foram executadas por casos de teste que são aprovados`, `É uma métrica, que dá uma confirmação verdadeira/falsa se todas as declarações são cobertas ou não`], answerIndex: 1, explanation: `A <b>cobertura de instruções (statements)</b> é a proporção (percentual) de instruções executáveis do código exercitadas pelos testes. É uma porcentagem, não uma contagem absoluta nem um simples 'sim/não'.` },
  { id: "c4-26", chapter: 4, prompt: `Qual declaração sobre a relação entre a cobertura de declarações e a cobertura de decisões é verdadeira?`, options: [`100% de cobertura de decisão também garante 100% de cobertura de declaração`, `100% de cobertura de declaração também garante 100% de cobertura de decisão`, `50% de cobertura de decisão também garante 50% de cobertura de declaração`, `A cobertura de decisão nunca pode chegar a 100%.`], answerIndex: 0, explanation: `A cobertura de <b>decisão é mais forte</b>: 100% de decisão implica automaticamente 100% de instrução, mas 100% de instrução não garante 100% de decisão. Por isso a primeira afirmação é a verdadeira.` },
  { id: "c4-27", chapter: 4, prompt: `Para qual das seguintes situações é adequado o teste exploratório?`, options: [`Quando a pressão do tempo requer a aceleração da execução de testes já especificados`, `Quando o sistema é desenvolvido de forma incremental, e não há carta de teste disponível`, `Quando houver testadores disponíveis que tenham conhecimento suficiente de aplicações e tecnologias similares`, `Quando já existe um conhecimento avançado do sistema, e é necessário fornecer provas de que ele deve ser testado intensivamente`], answerIndex: 2, explanation: `O <b>teste exploratório</b> é mais eficaz quando conduzido por testadores experientes, com bom conhecimento do domínio e de tecnologias similares. A experiência do testador é o que orienta a exploração.` },
  { id: "c4-28", chapter: 4, prompt: `O bônus de um funcionário deve ser calculado, não pode ser negativo, mas pode ser calculado até zero. O bônus é baseado na duração do emprego: menor ou igual a 2 anos; mais de 2 anos mas menos de 5 anos; 5 a 10 anos inclusive; mais de 10 anos. Qual é o número mínimo de casos de teste necessário para cobrir todas as partições de equivalência válidas para o cálculo do bônus?`, options: [`3`, `5`, `2`, `4`], answerIndex: 3, explanation: `As quatro faixas de tempo de emprego (≤2 anos; >2 e <5; 5–10; >10) formam <b>4 partições válidas</b>, cada uma exigindo um representante — logo, 4 casos de teste.` },
  { id: "c4-29", chapter: 4, prompt: `Um sistema de controle de velocidade e relatórios: se dirigir 50 km/h ou menos, nada acontece; mais rápido que 50 mas não mais que 55, é avisado; mais rápido que 55 mas não mais que 60, é multado; mais de 60, a carteira é suspensa. A velocidade está disponível como valor inteiro. Qual seria o conjunto mais provável de valores (km/h) identificado pela aplicação da análise de valores limite, onde apenas os valores nos limites das classes de equivalência são selecionados?`, options: [`0, 49, 50, 54, 59, 60`, `50, 55, 60`, `49, 50, 54, 55, 60, 62`, `50, 51, 55, 56, 60, 61`], answerIndex: 3, explanation: `Como a velocidade é um inteiro, cada limite de classe exige o próprio valor e seu vizinho imediato: 50/51, 55/56 e 60/61. Esse é o conjunto típico da análise de valor limite para esse problema.` },
  { id: "c4-30", chapter: 4, prompt: `Funcionários recebem bônus se trabalharem mais de um ano e atingirem uma meta acordada. Tabela de decisão: T1(Empregado>1ano=SIM, Objetivo acordado=NÃO, Objetivo alcançado=NÃO, Bônus=NÃO); T2(NÃO, NÃO, NÃO, NÃO); T3(NÃO, SIM, SIM, NÃO); T4(SIM, SIM, SIM, SIM). Qual dos seguintes casos de teste representa uma situação que pode acontecer na vida real, e está faltando na tabela de decisão acima?`, options: [`Condição 1 = SIM, Condição 2 = NÃO, Condição 3 = SIM, Ação = NÃO`, `Condição 1 = SIM, Condição 2 = SIM, Condição 3 = NÃO, Ação = SIM`, `Condição 1 = NÃO, Condição 2 = NÃO, Condição 3 = SIM, Ação = NÃO`, `Condição 1 = NÃO, Condição 2 = SIM, Condição 3 = NÃO, Ação = NÃO`], answerIndex: 3, explanation: `A tabela original não cobre a combinação em que o funcionário tem menos de 1 ano, mas já tem objetivo acordado e não alcançado — situação real e ausente, cuja ação é 'não paga bônus'. Por isso é o caso de teste faltante.` },
  { id: "c4-31", chapter: 4, prompt: `Uma aplicação de vídeo deve permitir a reprodução em: 640x480, 1280x720, 1600x1200, 1920x1080. Qual dos seguintes casos de teste é resultado da aplicação da técnica de particionamento de equivalência para testar este requisito?`, options: [`Verificar se a aplicação pode reproduzir um vídeo em uma tela de tamanho 1920x1080 (1 caso de teste)`, `Verificar se a aplicação pode reproduzir um vídeo em um display de tamanho 640x480 e 1920x1080 (2 casos de teste)`, `Verificar se a aplicação pode reproduzir um vídeo em cada um dos tamanhos de exibição na exigência (4 casos de teste)`, `Verificar se a aplicação pode reproduzir um vídeo em qualquer um dos tamanhos de tela na exigência (1 caso de teste)`], answerIndex: 2, explanation: `Como cada resolução é uma exigência distinta e específica (não uma faixa contínua), cada uma forma sua própria partição válida, exigindo <b>4 casos de teste</b> — um por resolução.` },
  { id: "c4-32", chapter: 4, prompt: `Qual dos itens a seguir fornece a MELHOR descrição de testes exploratórios?`, options: [`Uma prática de teste na qual uma investigação aprofundada dos antecedentes do objeto de teste é utilizada para identificar potenciais pontos fracos que são examinados pelos casos de teste.`, `Uma abordagem aos testes em que os testadores projetam e executam dinamicamente testes baseados em seu conhecimento, exploração do item de teste e nos resultados dos testes anteriores.`, `Uma abordagem de projeto de teste na qual as atividades de teste são planejadas como sessões ininterruptas de análise e projeto de teste.`, `Testes baseados na experiência, conhecimento e intuição do testador.`], answerIndex: 1, explanation: `O <b>teste exploratório</b> é a abordagem em que o testador projeta e executa testes dinamicamente, com base no seu conhecimento, na exploração do item e nos resultados anteriores. Essa é a definição do glossário ISTQB.` },
  { id: "c4-33", chapter: 4, prompt: `Qual dos seguintes MELHOR combina as descrições com as diferentes categorias de técnicas de teste? (1) A cobertura é medida com base em uma estrutura selecionada do objeto de teste. (2) O processamento dentro do objeto de teste é verificado. (3) Os testes são baseados na probabilidade de defeitos e sua distribuição. (4) Os desvios das exigências são verificados. (5) As histórias de usuários são usadas como base de teste. Usando: Preto - técnicas caixa-preta; Branco - técnicas caixa-branca; Experiência - técnicas baseadas na experiência.`, options: [`Preto-4, 5; Branco - 1, 2; Experiência - 3`, `Preto - 3; Branco - 1, 2; Experiência - 4, 5`, `Preto - 4; Branco - 1, 2; Experiência - 3, 5`, `Preto - 1, 3, 5; Branco - 2; Experiência - 4`], answerIndex: 0, explanation: `Caixa-preta verifica desvios de requisitos e usa histórias de usuário (4,5); caixa-branca mede cobertura estrutural e verifica o processamento interno (1,2); a baseada em experiência usa a probabilidade/distribuição de defeitos (3). Daí Preto-4,5; Branco-1,2; Experiência-3.` },
  { id: "c4-34", chapter: 4, prompt: `Um aplicativo de fitness mede o número de passos diários. Feedback: até 1000 "Preguiçoso!"; acima de 1000 até 2000 "Molenga!"; acima de 2000 até 4000 "Chegando lá!"; acima de 4000 até 6000 "Nada mal!"; acima de 6000 "Muito bom!". Qual dos seguintes conjuntos de entradas de teste alcançaria a MELHOR cobertura de partição de equivalência?`, options: [`0, 1000, 2000, 3000, 4000`, `1000, 2001, 4000, 4001, 6000`, `123, 2345, 3456, 4567, 5678`, `666, 999, 2222, 5555, 6666`], answerIndex: 3, explanation: `Um valor de cada uma das 5 partições válidas (≤1000; 1001–2000; 2001–4000; 4001–6000; >6000) garante 100% de cobertura de particionamento de equivalência. O conjunto que atinge todas as faixas é o correto.` },
  { id: "c4-35", chapter: 4, prompt: `Um gravador de radiação diário para plantas produz uma pontuação combinando horas de exposição ao sol (abaixo de 3h, 3 a 6h, acima de 6h) e intensidade média (muito baixa, baixa, média, alta). Casos de teste: T1(1,5h, Muito Baixa, 10); T2(7,0h, Média, 60); T3(0,5h, Muito Baixa, 10). Qual é o número mínimo de casos de teste adicionais necessários para garantir a cobertura total de TODAS as partições de equivalência de entrada válida?`, options: [`1`, `2`, `3`, `4`], answerIndex: 1, explanation: `Os casos T1–T3 já cobrem parte das partições de horas (3 faixas) e de intensidade (4 faixas); faltam partições ainda não exercitadas, que exigem <b>2 casos de teste adicionais</b> para completar a cobertura de todas as partições válidas.` },
  { id: "c4-36", chapter: 4, prompt: `Um aplicativo doméstico inteligente mede a temperatura média semanal. Feedback: até 10ºC "Gelado"; 11ºC a 15ºC "Refrigerado"; 16ºC a 19ºC "Agradável"; 20ºC a 22ºC "Quente"; acima de 22ºC "Muito quente". Usando BVA (somente valores Mínimos e Máximos), qual dos seguintes conjuntos de entradas de teste fornece o mais alto nível de cobertura de limite?`, options: [`0ºC, 11ºC, 20ºC, 22ºC, 23ºC`, `9ºC, 15ºC, 19ºC, 23ºC, 100ºC`, `10ºC, 16ºC, 19ºC, 22ºC, 23ºC`, `14ºC, 15ºC, 18ºC, 19ºC, 19ºC, 21ºC, 22ºC`], answerIndex: 2, explanation: `O conjunto correto cobre os valores mínimo e máximo de cada faixa (10, 16, 19, 22 e 23), maximizando a cobertura de limites com o menor número de valores. É o objetivo da BVA de mínimos e máximos.` },
  { id: "c4-37", chapter: 4, prompt: `Testes de tabela de decisão em um sistema de multa por excesso de velocidade. Casos já gerados para R1 (Velocidade>50=T, Zona escolar=T, Multa=F, Recolhimento=T) e R4 (F,F,F,F). Casos adicionais: DT1(55 km/h, Zona escolar); DT2(44 km/h, Zona escolar); DT3(66 km/h, Zona escolar); DT4(77 km/h, Fora de zona escolar). Quais dos dois casos de teste adicionais alcançariam cobertura total da tabela de decisão completa?`, options: [`DT1, DT2`, `DT2, DT3`, `DT2, DT4`, `DT3, DT4`], answerIndex: 2, explanation: `DT2 (44 km/h em zona escolar) e DT4 (77 km/h fora de zona escolar) completam as combinações de regras ainda não cobertas pelos casos originais R1 e R4. Juntos, atingem a cobertura total da tabela de decisão.` },
  { id: "c4-38", chapter: 4, prompt: `Qual das seguintes declarações MELHOR descreve como os casos de teste são derivados de um caso de uso?`, options: [`Os casos de teste são criados para exercitar comportamentos básicos, excepcionais e de erro definidos pelo sistema em teste, em colaboração com os atores.`, `Os casos de teste são derivados da identificação dos componentes incluídos no caso de uso e da criação de testes de integração.`, `Os casos de teste são gerados através da análise das interações dos atores com o sistema para garantir que as interfaces sejam fáceis de usar.`, `Os casos de teste são derivados para exercer cada um dos pontos de decisão nos fluxos do processo comercial, para atingir 100% de cobertura de decisão.`], answerIndex: 0, explanation: `Casos de teste baseados em <b>casos de uso</b> exercitam os fluxos básico, alternativos e de exceção definidos na interação entre atores e sistema. Não se limitam a integração nem a cobertura de decisão.` },
  { id: "c4-39", chapter: 4, prompt: `Qual das seguintes descrições de cobertura de declarações é CORRETA?`, options: [`A cobertura de declaração é uma medida do número de linhas de código fonte exercidas por testes.`, `A cobertura de declarações é uma medida da proporção de declarações executáveis no código fonte exercida por testes.`, `A cobertura de declaração é uma medida da porcentagem de linhas de código fonte (sem comentários) exercida por testes.`, `A cobertura de declarações é uma medida do número de declarações executáveis no código fonte exercido por testes.`], answerIndex: 1, explanation: `A definição correta usa a <b>proporção (percentual)</b> de instruções executáveis exercitadas, não a contagem de linhas nem de linhas sem comentário. Statement coverage é sempre relativa ao total de instruções executáveis.` },
  { id: "c4-40", chapter: 4, prompt: `Qual das seguintes descrições de cobertura de decisão é CORRETA?`, options: [`A cobertura de decisão é uma medida da porcentagem de caminhos possíveis através do código fonte exercida por testes.`, `A cobertura de decisão é uma medida da porcentagem dos fluxos comerciais através do componente exercido por testes.`, `A cobertura de decisão é uma medida das declarações "se" no código que são exercidas tanto com os resultados verdadeiros como falsos.`, `A cobertura de decisão é uma medida da proporção de resultados de decisão no código fonte exercida por testes.`], answerIndex: 3, explanation: `Por definição, a <b>cobertura de decisão</b> é a proporção de desfechos de decisão (resultados verdadeiro/falso) do código exercitados pelos testes. Não é a proporção de caminhos nem de fluxos de negócio.` },
  { id: "c4-41", chapter: 4, prompt: `Qual dos seguintes itens descreve MELHOR o conceito por trás da adivinhação de erros?`, options: [`A adivinhação de erros requer que você imagine que é o usuário do objeto de teste e adivinhe os erros que o usuário poderia cometer ao interagir com ele.`, `A adivinhação de erros envolve o uso de sua experiência pessoal de desenvolvimento e os erros que você cometeu como desenvolvedor.`, `A suposição de erros envolve o uso de seu conhecimento e experiência de defeitos encontrados no passado e erros típicos cometidos pelos desenvolvedores.`, `A adivinhação de erros exige que você duplique rapidamente a tarefa de desenvolvimento para identificar o tipo de erros que um desenvolvedor pode cometer.`], answerIndex: 2, explanation: `A <b>suposição de erro (error guessing)</b> usa o conhecimento e a experiência do testador sobre defeitos passados e erros típicos de desenvolvedores para prever onde o produto pode falhar.` },
  { id: "c4-42", chapter: 4, prompt: `O que é teste baseado em checklist?`, options: [`Uma técnica de teste na qual os testes são derivados com base no conhecimento do testador sobre falhas do passado, ou conhecimento geral de falhas`, `Uma técnica de teste baseada em uma análise da especificação de um componente ou sistema`, `Uma técnica de teste baseada na experiência em que o testador experiente usa uma lista de itens a serem anotados, verificados ou lembrados, ou um conjunto de regras, ou critérios contra os quais um produto deve ser verificado`, `Uma abordagem aos testes onde os testadores projetam e executam testes dinamicamente baseados em seu conhecimento, exploração do item de teste e nos resultados dos testes anteriores`], answerIndex: 2, explanation: `O <b>teste baseado em checklist</b> é uma técnica baseada em experiência: o testador usa uma lista de itens/critérios a verificar sistematicamente. Não deriva da análise da especificação nem é exploratório puro.` },

  // ---------------- Capítulo 5 ----------------
  { id: "c5-01", chapter: 5, prompt: "Critérios de entrada e de saída servem para:", options: [`Definir a linguagem de programação usada no projeto`, `Estabelecer condições para iniciar (entrada) e concluir (saída) uma atividade`, `Substituir completamente o plano de teste do projeto`, `Medir exclusivamente a cobertura de código alcançada`], answerIndex: 1, explanation: `Os <b>critérios de entrada</b> definem as condições para iniciar uma atividade e os <b>de saída</b>, as condições para concluí-la. No ágil, correspondem à Definition of Ready (DoR) e à Definition of Done (DoD).` },
  { id: "c5-02", chapter: 5, prompt: "A diferença entre risco de produto e risco de projeto é:", options: [`Produto trata de prazos da equipe; Projeto trata da qualidade do código`, `Produto: qualidade do produto (defeitos/falhas); Projeto: gestão (prazos, recursos, pessoas)`, `São sinônimos usados de forma intercambiável na gestão de teste`, `Ambos tratam exclusivamente do custo total do projeto`], answerIndex: 1, explanation: `O <b>risco de produto</b> afeta a qualidade do produto (defeitos, falhas); o <b>risco de projeto</b> afeta a gestão (prazos, recursos, pessoas, fornecedores). São categorias distintas de risco.` },
  { id: "c5-03", chapter: 5, prompt: "O nível de um risco é determinado por:", options: [`Apenas pela probabilidade de o evento ocorrer`, `A probabilidade combinada ao impacto`, `Apenas pelo custo estimado da correção`, `Pelo número de testadores alocados ao projeto`], answerIndex: 1, explanation: `O <b>nível de risco</b> é determinado pela combinação de probabilidade de ocorrência e impacto do evento. Não depende só da probabilidade nem só do custo de correção.` },
  { id: "c5-04", chapter: 5, prompt: "O teste baseado em risco usa a análise de risco para:", options: [`Eliminar a necessidade de documentar os testes realizados`, `Priorizar e alocar o esforço de teste conforme os riscos`, `Automatizar completamente todos os casos de teste do projeto`, `Definir qual linguagem de programação a equipe deve usar`], answerIndex: 1, explanation: `O <b>teste baseado em risco</b> usa a análise de risco para priorizar e alocar o esforço: testa-se antes e com mais profundidade o que tem maior risco. Não serve para escolher linguagem nem para automatizar tudo.` },
  { id: "c5-05", chapter: 5, prompt: "A pirâmide de testes sugere ter:", options: [`Mais testes de UI/E2E e poucos testes unitários (invertido)`, `Mais testes de baixo nível (unitários, rápidos/baratos) e menos de alto nível (UI/E2E)`, `O mesmo número de testes em todos os níveis da pirâmide`, `Apenas testes manuais executados pela equipe de QA`], answerIndex: 1, explanation: `A <b>pirâmide de testes</b> sugere uma base ampla de testes de baixo nível (unitários, rápidos e baratos) e um topo estreito de testes de UI/E2E (lentos, caros e frágeis). Isso equilibra rapidez de feedback e custo.` },
  { id: "c5-06", chapter: 5, prompt: "Qual item é essencial em um bom relatório de defeito?", options: [`O título e uma captura de tela, sem mais nenhum detalhe técnico`, `Passos para reproduzir, resultado esperado x obtido, severidade/prioridade e status`, `O nome do desenvolvedor responsável e a data de abertura, apenas`, `A data de abertura e o número da versão, sem descrição do problema`], answerIndex: 1, explanation: `Um bom <b>relatório de defeito</b> traz passos para reproduzir, resultado esperado × obtido, severidade/prioridade e status, além de ID e descrição. Só título e captura de tela não bastam.` },
  { id: "c5-07", chapter: 5, prompt: "Severidade e prioridade de um defeito diferem porque:", options: [`Severidade mede a urgência; prioridade mede o impacto técnico (invertido)`, `Severidade = impacto no sistema; prioridade = urgência da correção (negócio)`, `São sempre iguais e definidas pela mesma pessoa`, `Nenhuma das duas influencia o planejamento da correção`], answerIndex: 1, explanation: `A <b>severidade</b> mede o impacto técnico do defeito no sistema; a <b>prioridade</b> mede a urgência da correção do ponto de vista do negócio. Elas podem divergir (defeito grave, mas de baixa prioridade, e vice-versa).` },
  { id: "c5-08", chapter: 5, prompt: "Na estimativa por três pontos (PERT), a estimativa esperada é:", options: [`(otimista + pessimista) / 2, ignorando o cenário mais provável`, `(otimista + 4×mais provável + pessimista) / 6`, `mais provável × 3, sem considerar os extremos otimista/pessimista`, `(otimista × pessimista) / mais provável, uma média geométrica simples`], answerIndex: 1, explanation: `Na estimativa de três pontos (PERT), a estimativa esperada é E = (otimista + 4 × mais provável + pessimista) / 6. A fórmula reduz o peso dos cenários extremos.` },
  { id: "c5-09", chapter: 5, prompt: "A gerência de configuração, no teste, garante:", options: [`Corrigir automaticamente os defeitos encontrados durante o teste`, `Integridade e rastreabilidade dos itens de teste e testware, com versionamento`, `Executar os testes planejados conforme o cronograma definido`, `Escrever os requisitos que servirão de base para os testes`], answerIndex: 1, explanation: `A <b>gerência de configuração</b> mantém a integridade e a rastreabilidade dos itens de teste e do testware, com versionamento e controle de mudanças. Não corrige defeitos nem executa testes.` },
  { id: "c5-10", chapter: 5, prompt: "O relatório de conclusão de teste (test summary) serve para:", options: [`Formalizar o início do projeto e alocar a equipe de teste`, `Resumir as atividades e resultados de teste ao final de uma fase/marco`, `Substituir completamente o plano de teste elaborado antes`, `Registrar os detalhes de um único defeito encontrado`], answerIndex: 1, explanation: `O <b>relatório de conclusão (test summary)</b> resume as atividades e os resultados de teste ao final de uma fase/marco, apoiando decisões de liberação. Não substitui o plano nem registra um único defeito.` },
  { id: "c5-11", chapter: 5, prompt: "Planning poker é um exemplo de qual técnica de estimativa?", options: [`Baseada em razão, usando indicadores históricos de projetos anteriores`, `Baseada na opinião de especialistas (wideband Delphi)`, `Extrapolação de medições coletadas durante o próprio projeto`, `Estimativa de três pontos, combinando cenário otimista e pessimista`], answerIndex: 1, explanation: `O <b>planning poker</b> é uma variação do <b>wideband Delphi</b>: estimativa colaborativa baseada na opinião de especialistas (a própria equipe). Não é baseada em razão/índices nem em três pontos.` },
  { id: "c5-12", chapter: 5, prompt: "O Quadrante Q1 de teste (Brian Marick) contém:", options: [`Testes exploratórios e de usabilidade conduzidos manualmente`, `Testes de componente e integração de componentes, automatizados e incluídos no CI`, `Testes não funcionais e smoke tests voltados ao produto`, `Testes funcionais derivados de histórias de usuário`], answerIndex: 1, explanation: `O <b>Quadrante Q1</b> (Brian Marick) é voltado à tecnologia e apoia a equipe: testes de componente e de integração de componentes, automatizados e incluídos na integração contínua (CI).` },
  { id: "c5-13", chapter: 5, prompt: "O Quadrante Q3 de teste é caracterizado por:", options: [`Testes automatizados de componente voltados para tecnologia`, `Testes de negócio, exploratórios e de usabilidade, orientados ao usuário e geralmente manuais`, `Smoke tests e testes de performance incluídos no pipeline de CI`, `Testes de aceitação totalmente automatizados pela equipe`], answerIndex: 1, explanation: `O <b>Quadrante Q3</b> é voltado ao negócio e avalia o produto: testes de negócio, exploratórios e de usabilidade, orientados ao usuário e em geral manuais.` },
  { id: "c5-14", chapter: 5, prompt: "Na priorização de casos de teste por 'cobertura adicional', a ordem de execução é:", options: [`Primeiro os casos de teste mais curtos e fáceis de executar`, `O caso com maior cobertura primeiro; cada subsequente adiciona a maior cobertura incremental`, `Em ordem aleatória, sorteando os casos a cada execução`, `Na ordem em que os casos foram criados pela equipe`], answerIndex: 1, explanation: `Na priorização por <b>cobertura adicional</b>, executa-se primeiro o caso de maior cobertura e, em seguida, o que acrescenta a maior cobertura incremental. Assim ganha-se cobertura o mais rápido possível.` },
  { id: "c5-15", chapter: 5, prompt: "A 'baseline' no gerenciamento de configuração significa:", options: [`Um defeito de alta severidade encontrado durante a execução`, `Um item de configuração aprovado para teste, alterável apenas via processo formal`, `O plano inicial de teste elaborado antes do projeto começar`, `A primeira versão do código-fonte entregue pela equipe`], answerIndex: 1, explanation: `Uma <b>baseline</b> é um item de configuração aprovado para teste, que só pode ser alterado por um processo formal de mudança. Ela permite reverter e reproduzir resultados de forma confiável.` },
  { id: "c5-16", chapter: 5, prompt: "A análise de risco do produto pode influenciar os testes ao:", options: [`Eliminar completamente a necessidade de critérios de saída`, `Determinar escopo, níveis, técnicas, cobertura, esforço e priorização dos testes`, `Substituir por completo o plano de teste já elaborado`, `Definir apenas o prazo final de entrega do projeto`], answerIndex: 1, explanation: `A <b>análise de risco do produto</b> influencia escopo, níveis e tipos de teste, técnicas, cobertura, esforço e priorização. Ela não elimina critérios de saída nem substitui o plano de teste.` },
  { id: "c5-17", chapter: 5, prompt: "Qual é a diferença entre DoR (Definition of Ready) e DoD (Definition of Done) no ágil?", options: [`São termos equivalentes usados por diferentes frameworks ágeis`, `DoR = critérios de entrada (para iniciar); DoD = critérios de saída (para considerar concluído)`, `DoD deve ser satisfeito antes de DoR, invertendo a ordem usual`, `DoR aplica-se apenas ao produto; DoD aplica-se apenas à iteração`], answerIndex: 1, explanation: `A <b>DoR (Definition of Ready)</b> reúne os critérios de entrada para iniciar o desenvolvimento/teste; a <b>DoD (Definition of Done)</b> reúne os critérios de saída para considerar algo concluído/liberável.` },
  { id: "c5-18", chapter: 5, prompt: "O relatório de PROGRESSO de teste difere do relatório de CONCLUSÃO principalmente porque:", options: [`Relatórios de progresso são sempre mais formais que os de conclusão`, `Progresso é gerado regularmente durante o teste; conclusão sumariza ao final de uma fase/marco`, `Apenas o relatório de conclusão inclui qualquer tipo de métrica`, `São idênticos em conteúdo, mudando apenas o título do documento`], answerIndex: 1, explanation: `O relatório de <b>progresso</b> é gerado regularmente durante a execução, para acompanhar o andamento; o de <b>conclusão</b> sumariza uma fase/marco completo e inclui lições aprendidas. Têm propósitos e momentos diferentes.` },
  { id: "c5-19", chapter: 5, prompt: "Na estimativa baseada em ÍNDICES (razão), se a proporção histórica dev:teste é 3:2 e o esforço de dev estimado é 600 hh, o esforço de teste estimado é:", options: ["300 hh", "400 hh", "200 hh", "900 hh"], answerIndex: 1, explanation: `Com proporção histórica dev:teste de 3:2 e 600 hh de desenvolvimento, o esforço de teste estimado é (2/3) × 600 = <b>400 hh</b>. Essa é a estimativa baseada em índices (razão).` },
  { id: "c5-20", chapter: 5, prompt: `Qual das seguintes declarações MELHOR descreve como as tarefas são divididas entre o gerente de testes e o testador?`, options: [`O gerente de testes planeja as atividades de teste e escolhe os padrões a serem seguidos, enquanto o testador escolhe as ferramentas e estabelece as diretrizes de uso.`, `O gerente de testes planeja, coordena e controla as atividades de teste, enquanto o testador automatiza os testes`, `O gerente de testes planeja, monitora e controla as atividades de teste, enquanto o testador projeta os testes e decide sobre a liberação do objeto de teste`, `O gerente de testes planeja e organiza os testes e especifica os casos de teste, enquanto o testador executa os testes`], answerIndex: 1, explanation: `O <b>gerente de testes</b> planeja, coordena e controla as atividades de teste; o <b>testador</b> executa as tarefas técnicas, como projetar, automatizar e executar testes. A decisão de liberação não cabe ao testador.` },
  { id: "c5-21", chapter: 5, prompt: `Qual das seguintes métricas seria a mais útil para monitorar durante a execução do teste?`, options: [`Porcentagem de casos de teste executados.`, `Número médio de testadores envolvidos na execução do teste.`, `Cobertura dos requisitos pelo código fonte.`, `Porcentagem de casos de teste já criados e revisados.`], answerIndex: 0, explanation: `Durante a <b>execução</b>, a métrica mais útil para acompanhar o progresso é o percentual de casos de teste já executados. Métricas de criação/revisão são mais úteis em fases anteriores.` },
  { id: "c5-22", chapter: 5, prompt: `Qual dos seguintes aspectos pode afetar e fazer parte do planejamento (inicial) do teste?`, options: [`Limitações orçamentárias`, `O diário de testes mantido pela equipe durante a execução`, `A taxa de falha observada no sistema em produção`, `Os casos de uso já implementados no sistema atual`], answerIndex: 0, explanation: `Restrições de <b>orçamento</b> afetam diretamente o escopo e a estratégia definidos no planejamento inicial do teste. Diário de testes, taxa de falha em produção e casos já implementados surgem depois, não no planejamento inicial.` },
  { id: "c5-23", chapter: 5, prompt: `Qual das listas a seguir contém apenas os critérios típicos de saída dos testes?`, options: [`Medidas de confiabilidade, cobertura do teste, cronograma e status sobre a correção de defeitos e riscos remanescentes`, `Medidas de confiabilidade, cobertura de teste, grau de independência do testador e completude do produto`, `Medidas de confiabilidade, cobertura de teste, custo do teste, disponibilidade do ambiente de teste, tempo de colocação no mercado e completude do produto`, `Tempo para comercialização, defeitos restantes, qualificação do testador, disponibilidade de casos de uso testável, cobertura de teste e custo do teste`], answerIndex: 0, explanation: `Critérios de <b>saída</b> típicos incluem medidas de confiabilidade, cobertura de teste, cronograma e o status da correção de defeitos e riscos remanescentes. Grau de independência e qualificação do testador não são critérios de saída.` },
  { id: "c5-24", chapter: 5, prompt: `Qual dos itens a seguir NÃO está incluído em um relatório resumido de teste?`, options: [`Definição de critérios de aprovação/reprovação e objetivos dos testes`, `Os desvios observados em relação à abordagem de teste planejada`, `As medições do progresso real frente aos critérios de saída`, `A avaliação da qualidade do objeto de teste ao final da fase`], answerIndex: 0, explanation: `Critérios de aprovação/reprovação e objetivos de teste são definidos no <b>plano de teste</b>, não no relatório resumo — que reporta resultados observados, desvios e a avaliação da qualidade ao final. Por isso essa é a opção que NÃO pertence ao resumo.` },
  { id: "c5-25", chapter: 5, prompt: `O projeto desenvolve um termostato de aquecimento "inteligente" com algoritmos modelados em Matlab/Simulink executados em servidor conectado à Internet. O gerente de teste definiu: 1. O teste de aceite para todo o sistema é executado como um teste baseado na experiência. 2. Os algoritmos de controle no servidor são verificados em relação ao padrão do regulamento de economia de energia. 3. O teste funcional do termostato é executado como um teste baseado em risco. 4. Os testes de segurança de dados/comunicação são executados com especialistas externos. Que quatro tipos comuns de estratégias/abordagens de teste o gerente de testes implementou?`, options: [`Metódico, analítico, reativo e avesso à regressão`, `Analítico, conforme às normas, consultivo e reativo`, `Baseada em modelos, metódica, analítica e consultiva`, `Regressão-aversão, consultiva, reativa e metódica`], answerIndex: 1, explanation: `Aceitação baseada em experiência = abordagem <b>reativa</b>; verificação contra normas = <b>conforme às normas</b>; teste baseado em risco = <b>analítico</b>; testes com especialistas externos = <b>consultivo</b>. Essas são as quatro abordagens implementadas.` },
  { id: "c5-26", chapter: 5, prompt: `Qual das seguintes é uma característica de uma abordagem baseada em métricas para a estimativa de teste?`, options: [`Orçamento que foi utilizado por um projeto de teste anterior semelhante.`, `Experiência geral coletada em entrevistas com gerentes de testes.`, `Estimativa de esforço para automação de testes acordada na equipe de teste.`, `Mediana dos cálculos coletados de especialistas empresariais.`], answerIndex: 0, explanation: `A abordagem <b>baseada em métricas</b> usa dados históricos — por exemplo, o orçamento gasto em um projeto de teste anterior semelhante. Opinião de especialistas e médias de entrevistas caracterizam a abordagem baseada em especialistas.` },
  { id: "c5-27", chapter: 5, prompt: `Você está testando uma máquina de café que prepara diferentes tipos com base em tamanho, açúcar, leite e xarope. Você escreve um relatório de defeito com: Título (Baixa temperatura do café); Resumo (leite selecionado causa demora e temperatura abaixo de 40°C); Resultado esperado (75°C); Grau de risco (Médio); Prioridade (Normal). Que informação valiosa foi omitida no relatório de defeitos acima?`, options: [`Os resultados reais obtidos durante a execução dos testes`, `Identificação da versão testada do software`, `O status atual do defeito registrado no sistema`, `Sugestões para melhorar o caso de teste utilizado`], answerIndex: 1, explanation: `Falta ao relatório a <b>identificação da versão testada do software</b> — informação essencial para reproduzir e localizar o defeito. Resultado esperado, risco e prioridade já constam do relato.` },
  { id: "c5-28", chapter: 5, prompt: `Qual das seguintes tarefas é MUITO MAIS EFICIENTE quando executada pelo gerente de testes?`, options: [`Escrever relatórios resumidos de testes com base nas informações coletadas durante os testes.`, `Revisar detalhadamente os testes já desenvolvidos por outros membros da equipe.`, `Preparar e adquirir os dados de teste necessários para a execução.`, `Analisar, revisar e avaliar os requisitos, especificações e modelos de testabilidade.`], answerIndex: 0, explanation: `Consolidar as informações do projeto em <b>relatórios de resumo de teste</b> é tarefa típica do gerente de testes, que tem a visão geral. Preparar dados, revisar testes e analisar requisitos são tarefas mais técnicas, do testador.` },
  { id: "c5-29", chapter: 5, prompt: `Dados os seguintes exemplos: (1) Orçamento original de $30.000 mais contingência de $7.000 foi gasto. (2) 96% dos testes planejados foram executados e os restantes estão fora do escopo. (3) O ambiente de teste de desempenho foi projetado, montado e verificado. (4) Status atual: nenhum defeito crítico pendente e dois de alta prioridade. (5) As especificações de projeto do piloto automático foram revisadas e retrabalhadas. (6) O componente de cálculo da taxa de imposto passou nos testes unitários. Qual dos seguintes os classifica MELHOR como critérios de entrada e saída?`, options: [`Critérios de entrada - 5, 6; Critérios de saída - 1, 2, 3, 4.`, `Critérios de entrada - 2, 3, 6; Critérios de saída - 1, 4, 5.`, `Critérios de entrada - 1, 3; Critérios de saída - 2, 4, 5, 6.`, `Critérios de entrada - 3, 5, 6; Critérios de saída - 1, 2, 4.`], answerIndex: 3, explanation: `Ambiente pronto, especificações revisadas e testes unitários aprovados (3, 5, 6) são pré-condições para iniciar o teste (entrada); orçamento gasto, percentual executado e status dos defeitos (1, 2, 4) são condições para concluir (saída).` },
  { id: "c5-30", chapter: 5, prompt: `Prioridades e dependências: TC1(Alta, dep. técnica TC4); TC2(Baixa); TC3(Alta, dep. lógica TC4); TC4(Média); TC5(Baixa, dep. lógica TC2); TC6(Média, dep. técnica TC5). Qual dos seguintes cronogramas de execução de testes CONSIDERA MELHOR as prioridades e dependências técnicas e lógicas?`, options: [`TC1 - TC3 - TC4 - TC6 - TC2 - TC5`, `TC4 - TC3 - TC1 - TC2 - TC5 - TC6`, `TC4 - TC1 - TC3 - TC5 - TC6 - TC2`, `TC4 - TC2 - TC5 - TC1 - TC3 - TC6`], answerIndex: 1, explanation: `A ordem correta respeita as dependências: TC4 antes de TC1 e TC3 (dependências técnica/lógica); TC2 antes de TC5; e TC5 antes de TC6. O cronograma que satisfaz todas essas dependências e prioridades é o correto.` },
  { id: "c5-31", chapter: 5, prompt: `Qual das seguintes afirmações sobre os métodos de estimativa de teste é CORRETA?`, options: [`Com a abordagem baseada em métricas, a estimativa é baseada em medidas de teste do projeto e só está disponível após o início dos testes.`, `Com a abordagem baseada em especialistas, um grupo de usuários experientes identificados pelo cliente recomenda o orçamento de teste necessário.`, `Com a abordagem baseada em especialistas, os gerentes de testes responsáveis pelas diferentes atividades de teste preveem o esforço de teste esperado.`, `Com a abordagem baseada em métricas, uma média dos custos de teste registrados de vários projetos passados é usada como orçamento de teste.`], answerIndex: 2, explanation: `Na abordagem <b>baseada em especialistas</b>, os responsáveis pelas atividades de teste estimam o esforço com base na sua experiência. A baseada em métricas usa medições do próprio projeto ou de projetos passados.` },
  { id: "c5-32", chapter: 5, prompt: `Qual dos seguintes define MELHOR o nível de risco?`, options: [`O nível de risco é calculado somando as probabilidades de todas as situações problemáticas e os danos financeiros que delas resultam.`, `O nível de risco é estimado pela multiplicação da probabilidade de uma ameaça ao sistema pela chance de que a ameaça ocorra e resulte em dano financeiro.`, `O nível de risco é determinado por uma combinação da probabilidade de um evento indesejável e o impacto esperado desse evento.`, `O nível de risco é a soma de todos os perigos potenciais de um sistema multiplicada pela soma de todas as perdas potenciais desse sistema.`], answerIndex: 2, explanation: `O <b>nível de risco</b> é uma combinação da probabilidade de um evento indesejado com o impacto esperado desse evento. Não é soma de probabilidades nem de perdas.` },
  { id: "c5-33", chapter: 5, prompt: `Qual dos seguintes é o mais provável de ser um exemplo de risco de PRODUTO?`, options: [`As características de segurança esperadas podem não ser suportadas pela arquitetura do sistema.`, `Os desenvolvedores podem não ter tempo para corrigir todos os defeitos encontrados pela equipe de teste.`, `Os casos de teste podem não oferecer cobertura total dos requisitos especificados.`, `O ambiente de teste de desempenho pode não estar pronto antes que o sistema esteja pronto para entrega.`], answerIndex: 0, explanation: `Um <b>risco de produto</b> afeta a qualidade do sistema em si — por exemplo, a arquitetura não suportar as características de segurança esperadas. Prazos de correção e prontidão de ambiente são riscos de projeto.` },
  { id: "c5-34", chapter: 5, prompt: `Qual dos seguintes é o MENOS provável de ser um exemplo de análise de risco do produto INFLUENCIANDO CORRETAMENTE os testes?`, options: [`O impacto potencial das falhas de segurança foi identificado como particularmente alto, portanto os testes de segurança foram priorizados.`, `Os testes constataram que a qualidade do módulo de rede é superior ao esperado, portanto não serão realizados testes adicionais nessa área.`, `Os usuários tiveram problemas com a interface do sistema anterior, de modo que testes de usabilidade adicionais estão planejados para o substituto.`, `O tempo necessário para carregar as páginas web é crucial para o sucesso do novo site, por isso foi empregado um especialista em testes de desempenho.`], answerIndex: 1, explanation: `Resultados de teste indicando boa qualidade não devem, sozinhos, eliminar testes futuros de uma área — isso não é a análise de risco de produto influenciando corretamente o planejamento. As demais opções são exemplos legítimos dessa influência.` },
  { id: "c5-35", chapter: 5, prompt: `Você está testando um sistema de reserva de trens e notou que o sistema ocasionalmente relata que não há trens disponíveis quando deveria haver. Você já forneceu resumo do defeito e versão do sistema testado. Informações adicionais possíveis: (1) Grau de impacto (gravidade); (2) Identificação do item de teste; (3) Detalhes do ambiente de teste; (4) Urgência/prioridade; (5) Resultados reais; (6) Referência à especificação do caso de teste. Qual destas informações é a mais útil para incluir no relatório de defeitos?`, options: [`1, 2, 6`, `1, 4, 5, 6`, `2, 3, 4, 5`, `3, 5, 6`], answerIndex: 3, explanation: `Detalhes do ambiente de teste, resultados reais e referência à especificação do caso de teste (3, 5, 6) são as informações mais úteis para completar o relatório, já que resumo e versão já foram informados.` },

  // ---------------- Capítulo 6 ----------------
  { id: "c6-01", chapter: 6, prompt: "Qual é um risco comum da automação de testes?", options: [`Reduzir totalmente a necessidade de esforço humano na equipe`, `Expectativas irreais, subestimar a manutenção dos scripts e excesso de confiança na ferramenta`, `Aumentar a repetibilidade dos resultados obtidos em cada execução`, `Fornecer métricas objetivas sobre a qualidade do produto`], answerIndex: 1, explanation: `Um risco comum da <b>automação de testes</b> é criar expectativas irreais, subestimar o custo de manutenção dos scripts e confiar demais na ferramenta. Aumentar a repetibilidade e dar métricas objetivas são benefícios, não riscos.` },
  { id: "c6-02", chapter: 6, prompt: "Um benefício típico de ferramentas de teste é:", options: [`Substituir completamente a análise crítica feita por humanos`, `Reduzir trabalho repetitivo e aumentar consistência, repetibilidade e acesso a informações objetivas`, `Garantir que o software entregue esteja livre de defeitos`, `Eliminar a necessidade de planejamento e estratégia de teste`], answerIndex: 1, explanation: `Ferramentas de teste reduzem o trabalho repetitivo e aumentam a consistência, a repetibilidade e o acesso a informações objetivas sobre o teste. Elas não substituem o julgamento humano nem garantem software sem defeitos.` },
  { id: "c6-03", chapter: 6, prompt: "Ao introduzir uma ferramenta de teste na organização, uma boa prática é:", options: [`Implantar a ferramenta para toda a organização de uma só vez`, `Começar com um projeto-piloto para avaliar o ajuste antes de expandir`, `Escolher a ferramenta sem avaliar as necessidades da equipe`, `Eliminar o treinamento para acelerar a adoção da ferramenta`], answerIndex: 1, explanation: `Ao introduzir uma ferramenta, a boa prática é começar com um <b>projeto-piloto</b> para avaliar o encaixe com o contexto antes de expandir. Implantar tudo de uma vez ou pular o treinamento aumenta o risco de fracasso.` },
  { id: "c6-04", chapter: 6, prompt: "Ferramentas de execução de teste são mais valiosas para:", options: [`Substituir completamente a fase de design dos testes`, `Automatizar reteste e regressão repetitivos`, `Escrever os requisitos que servirão de base para os testes`, `Gerenciar os riscos identificados no projeto`], answerIndex: 1, explanation: `As ferramentas de execução de teste são mais valiosas para automatizar <b>reteste e regressão</b> repetitivos — tarefas frequentes e mecânicas. Não substituem o projeto de teste nem gerenciam riscos.` },
  { id: "c6-05", chapter: 6, prompt: "Qual categoria de ferramenta de teste dá suporte a testes que são 'difíceis ou impossíveis de serem realizados manualmente'?", options: [`Ferramentas de colaboração (chat, quadros compartilhados da equipe)`, `Ferramentas de teste não funcional (performance, segurança)`, `Ferramentas de gerenciamento (requisitos, testes e defeitos)`, `Ferramentas de projeto e implementação (geração de casos e dados)`], answerIndex: 1, explanation: `As ferramentas de <b>teste não funcional</b> (carga, stress, desempenho, segurança) executam cenários difíceis ou impossíveis de reproduzir manualmente. É onde a automação é praticamente indispensável.` },
  { id: "c6-06", chapter: 6, prompt: "A dependência do fornecedor é um risco da automação porque:", options: [`O fornecedor está sempre melhorando a ferramenta continuamente`, `O fornecedor pode fechar, aposentar a ferramenta, vendê-la ou fornecer suporte deficiente`, `Ferramentas de terceiros são sempre mais baratas que as internas`, `O fornecedor garante suporte técnico 24 horas por dia`], answerIndex: 1, explanation: `A <b>dependência do fornecedor</b> é um risco porque a empresa pode fechar, aposentar ou vender a ferramenta, ou oferecer suporte deficiente — deixando a equipe exposta. Por isso convém avaliar o fornecedor antes de adotar.` },
  { id: "c6-07", chapter: 6, prompt: "Ferramentas de DevOps no contexto de teste servem para:", options: [`Substituir completamente a análise estática do código`, `Suportar o pipeline de entrega CI/CD, rastreamento de fluxo e builds automatizadas`, `Gerenciar exclusivamente os defeitos abertos pela equipe`, `Criar manualmente os dados de teste necessários`], answerIndex: 1, explanation: `As ferramentas de <b>DevOps</b> apoiam o pipeline de entrega CI/CD, o rastreamento do fluxo de trabalho e a automação de builds. Elas dão suporte à integração e entrega contínuas, não substituem a análise estática.` },
  { id: "c6-08", chapter: 6, prompt: `Qual dos seguintes é o MAIS provável que seja um benefício das ferramentas de execução de testes?`, options: [`É fácil criar testes de regressão.`, `É fácil manter o controle de versão dos ativos de teste.`, `É fácil projetar testes para testes de segurança.`, `É fácil executar testes de regressão.`], answerIndex: 3, explanation: `O principal benefício das ferramentas de <b>execução de teste</b> é tornar fácil e rápido <b>executar (reexecutar)</b> os testes de regressão. Criar os testes, controlar versões ou projetar testes de segurança são outras atividades.` },
  { id: "c6-09", chapter: 6, prompt: `Qual das seguintes ferramentas de teste é mais adequada para desenvolvedores do que para testadores?`, options: [`Ferramentas de gerenciamento de requisitos.`, `Ferramentas de gerenciamento da configuração.`, `Ferramentas de gerenciamento de defeitos.`, `Ferramentas de teste de desempenho.`], answerIndex: 2, explanation: `As ferramentas de <b>gerenciamento de defeitos</b> são, no dia a dia, mais usadas pelos desenvolvedores para acompanhar e corrigir defeitos do que pelos testadores. As demais opções servem mais a outros papéis.` },
  { id: "c6-10", chapter: 6, prompt: `Dadas as seguintes atividades de teste e ferramentas de teste: (1) Medição de desempenho e análise dinâmica; (2) Execução de testes e registro; (3) Gerenciamento de testes e defeitos; (4) Projeto do teste. (a) Ferramentas de cobertura de requisitos; (b) Ferramentas de análise dinâmica; (c) Ferramentas de preparação de dados de teste; (d) Ferramentas de gerenciamento de defeitos. Qual dos seguintes MELHOR corresponde às atividades e ferramentas?`, options: [`1-B, 2-C, 3-D, 4-A`, `1-B, 2-D, 3-C, 4-A`, `1-B, 2-A, 3-D, 4-C`, `1-D, 2-B, 3-C, 4-A`], answerIndex: 2, explanation: `Medição de desempenho/análise dinâmica usa ferramentas de análise dinâmica (b); execução e registro usam ferramentas de cobertura (a); gerenciamento de testes/defeitos usa ferramentas de gerenciamento de defeitos (d); projeto do teste usa ferramentas de preparação de dados (c). Daí 1-b, 2-a, 3-d, 4-c.` },
  { id: "c6-11", chapter: 6, prompt: `Qual dos seguintes é o mais provável de ser usado como motivo para usar um projeto piloto para introduzir uma ferramenta em uma organização?`, options: [`A necessidade de avaliar como a ferramenta se ajusta aos processos e práticas existentes e determinar o que precisaria mudar.`, `A necessidade de avaliar as habilidades de automação de testes e as necessidades de treinamento, mentoria e coaching dos testadores que irão utilizar a ferramenta.`, `A necessidade de avaliar se a ferramenta fornece a funcionalidade necessária e não duplica as ferramentas de teste existentes.`, `A necessidade de avaliar o fornecedor de ferramentas em termos de treinamento e outros tipos de apoio que eles fornecem.`], answerIndex: 0, explanation: `Um <b>projeto-piloto</b> serve principalmente para avaliar como a ferramenta se encaixa nos processos e práticas já existentes, revelando o que precisaria mudar antes da adoção ampla. Avaliar habilidades, funcionalidade ou o fornecedor são objetivos secundários.` },

  /* ===================================================================
     Questões do Exame Exemplo Oficial ISTQB® CTFL v4.0 (Conjunto A),
     traduzido pelo BSTQB. Reproduzidas com atribuição, conforme a
     licença do documento de exemplo. ISTQB® é marca registrada do
     International Software Testing Qualifications Board.
     (Questões 13, 14, 21, 22, 23, 33, 34 e 38 do formulário são baseadas
     em imagens/diagramas e não foram importadas.)
     =================================================================== */

  // ---- Capítulo 1 (Sample Exam A: Q1–Q8) ----
  { id: "c1-35", chapter: 1, prompt: `Qual das seguintes afirmações descreve um objetivo de teste VÁLIDO?`, options: [`Provar que não há defeitos não corrigidos no sistema em teste.`, `Provar que não haverá falhas após a implantação do sistema em produção.`, `Reduzir o nível de risco do objeto de teste e aumentar a confiança no nível de qualidade.`, `Verificar se não há combinações de entradas não testadas.`], answerIndex: 2, explanation: `Reduzir o risco e <b>aumentar a confiança na qualidade</b> é um objetivo típico de teste. As demais são impossíveis: o teste mostra a presença de defeitos, mas não prova a ausência, e o teste exaustivo (todas as combinações) é impraticável.` },
  { id: "c1-36", chapter: 1, prompt: `Qual das opções a seguir é um exemplo que contribui para o SUCESSO das atividades de teste?`, options: [`O envolvimento dos testadores em várias atividades do ciclo de vida (SDLC) ajuda a detectar defeitos nos produtos de trabalho.`, `Os testadores procuram não interagir com os desenvolvedores durante a codificação, para não atrapalhá-los.`, `Testadores que colaboram com os usuários finais melhoram os relatórios de defeitos durante a integração de componentes.`, `Testadores certificados sempre modelam casos de teste muito melhores do que os não certificados.`], answerIndex: 0, explanation: `Envolver os testadores cedo e ao longo do SDLC (abordagem <b>shift-left</b>) permite encontrar defeitos nos produtos de trabalho antes que se propaguem. As outras opções descrevem isolamento entre papéis ou generalizações sem fundamento.` },
  { id: "c1-37", chapter: 1, prompt: `Você é testador em uma equipe que produz um sistema de forma incremental. Durante várias iterações, nenhuma alteração foi feita nos casos de teste de regressão existentes e nenhum novo defeito de regressão foi encontrado. Seu gerente está satisfeito, mas você não. Qual princípio de teste explica seu ceticismo?`, options: [`Os testes se desgastam (paradoxo do pesticida).`, `A ausência de erros é uma falácia.`, `Os defeitos se agrupam (defect clustering).`, `É impossível realizar testes exaustivos.`], answerIndex: 0, explanation: `Repetir os mesmos testes sem revisá-los faz com que parem de encontrar novos defeitos — é o <b>paradoxo do pesticida</b>. A falta de novos defeitos pode indicar apenas que os testes se esgotaram, e não que o sistema está livre de defeitos; é preciso revisar e criar novos testes.` },
  { id: "c1-38", chapter: 1, prompt: `Sua equipe desenvolve um app de pedidos de comida e, nesta iteração, vai implementar o pagamento. Qual das atividades a seguir faz parte da ANÁLISE de teste?`, options: [`Estimar que testar a integração com o serviço de pagamento levará 8 dias/homem.`, `Decidir que a equipe deve testar se é possível efetuar o pagamento com muitos usuários simultâneos.`, `Usar análise de valor limite (BVA) para derivar dados de teste para o valor mínimo permitido de pagamento.`, `Analisar a discrepância entre o resultado real e o esperado após executar um caso de teste de pagamento com cartão e relatar um defeito.`], answerIndex: 1, explanation: `A <b>análise de teste</b> responde "o que testar", identificando condições de teste — como decidir testar o pagamento sob carga de muitos usuários. Estimar esforço é planejamento; derivar dados com BVA é projeto/implementação; analisar a discrepância e relatar o defeito é execução.` },
  { id: "c1-39", chapter: 1, prompt: `Quais dos seguintes fatores têm influência SIGNIFICATIVA no processo de teste? (1) o SDLC adotado; (2) o número de defeitos detectados em projetos anteriores; (3) os riscos identificados do produto; (4) novos requisitos regulatórios; (5) o número de testadores certificados na organização.`, options: [`1 e 2 têm influência significativa; 3, 4 e 5 não.`, `1, 3 e 4 têm influência significativa; 2 e 5 não.`, `2, 4 e 5 têm influência significativa; 1 e 3 não.`, `3 e 5 têm influência significativa; 1, 2 e 4 não.`], answerIndex: 1, explanation: `O <b>SDLC</b>, os <b>riscos do produto</b> e as <b>restrições regulatórias</b> moldam diretamente o processo de teste. O número de defeitos de projetos passados e a quantidade de testadores certificados não são fatores contextuais determinantes segundo o syllabus.` },
  { id: "c1-40", chapter: 1, prompt: `Quais DUAS das tarefas a seguir pertencem PRINCIPALMENTE a um papel de teste? (A) Configurar ambientes de teste; (B) Manter o backlog do produto; (C) Projetar soluções para novos requisitos; (D) Criar o plano de teste; (E) Relatar a cobertura de teste alcançada.`, options: [`A e E`, `B e D`, `A e D`, `C e E`, `B e C`], answerIndex: 0, explanation: `Configurar ambientes de teste (A) e relatar a cobertura alcançada (E) são tarefas típicas do papel de teste. Manter o backlog (B) e projetar soluções (C) cabem a outros papéis, e criar o plano de teste (D) é uma tarefa de gerência de teste.` },
  { id: "c1-41", chapter: 1, prompt: `Quais das seguintes habilidades são as MAIS importantes para um testador? (1) ter conhecimento do domínio; (2) criar uma visão do produto; (3) ser um bom membro da equipe; (4) planejar e organizar o trabalho da equipe; (5) pensamento crítico.`, options: [`2 e 4 são importantes; 1, 3 e 5 não.`, `1, 3 e 5 são importantes; 2 e 4 não.`, `1, 2 e 5 são importantes; 3 e 4 não.`, `3 e 4 são importantes; 1, 2 e 5 não.`], answerIndex: 1, explanation: `<b>Conhecimento do domínio</b>, ser um <b>bom membro da equipe</b> e o <b>pensamento crítico</b> são habilidades centrais do testador. Criar a visão do produto e planejar/organizar o trabalho da equipe são atribuições de outros papéis (product owner, gestão).` },
  { id: "c1-42", chapter: 1, prompt: `Como a abordagem de "equipe inteira" (whole-team) se manifesta nas interações entre os testadores e os representantes de negócio?`, options: [`Os representantes de negócio decidem sobre as abordagens de automação de testes.`, `Os testadores ajudam os representantes de negócio a definir a estratégia de teste sozinhos.`, `Os representantes de negócio não participam da abordagem de equipe inteira.`, `Os testadores ajudam os representantes de negócio a criar testes de aceite adequados.`], answerIndex: 3, explanation: `Na abordagem de <b>equipe inteira</b>, todos colaboram pela qualidade: os testadores apoiam os representantes de negócio a escrever bons <b>testes de aceite</b>, aproveitando o conhecimento de negócio de cada um.` },

  // ---- Capítulo 2 (Sample Exam A: Q9–Q12) ----
  { id: "c2-26", chapter: 2, prompt: `Considere a regra: "para cada atividade do SDLC, há uma atividade de teste correspondente". Em quais modelos de SDLC essa regra é válida?`, options: [`Somente em modelos sequenciais.`, `Somente em modelos iterativos.`, `Somente em modelos iterativos e incrementais.`, `Em modelos sequenciais, incrementais e iterativos.`], answerIndex: 3, explanation: `O princípio "cada atividade de desenvolvimento tem uma atividade de teste correspondente" é um <b>bom princípio de teste em qualquer SDLC</b> — sequencial, incremental ou iterativo.` },
  { id: "c2-27", chapter: 2, prompt: `Qual das seguintes afirmações descreve MELHOR a abordagem de desenvolvimento orientado por testes de aceite (ATDD)?`, options: [`No ATDD, os critérios de aceite são criados no formato dado/quando/então.`, `No ATDD, os casos de teste são criados no teste de componentes e orientados ao código.`, `No ATDD, os testes são criados a partir dos critérios de aceite para orientar o desenvolvimento do software.`, `No ATDD, os testes se baseiam no comportamento desejado, o que facilita a compreensão da equipe.`], answerIndex: 2, explanation: `No <b>ATDD</b>, os testes de aceite são derivados dos <b>critérios de aceite antes do código</b> e orientam o desenvolvimento. As outras opções descrevem características do formato dado/quando/então ou do BDD, não a essência do ATDD.` },
  { id: "c2-28", chapter: 2, prompt: `Qual das opções a seguir NÃO é um exemplo da abordagem shift-left?`, options: [`Revisar os requisitos do usuário antes que sejam formalmente aceitos pelos stakeholders.`, `Escrever um teste de componente antes que o código correspondente seja escrito.`, `Executar um teste de eficiência de performance de um componente durante o teste de componente.`, `Escrever um script de teste antes de definir o processo de gerenciamento de configuração.`], answerIndex: 3, explanation: `O <b>shift-left</b> antecipa atividades de teste no ciclo (revisar requisitos cedo, testar componentes antes, antecipar testes não funcionais). Escrever um script antes de definir a gestão de configuração não antecipa nenhuma atividade de teste no SDLC — não é shift-left.` },
  { id: "c2-29", chapter: 2, prompt: `Qual argumento você usaria para convencer seu gerente a organizar retrospectivas ao final de cada ciclo de lançamento?`, options: [`As retrospectivas são muito populares e os clientes gostariam que as adicionássemos.`, `Elas economizam dinheiro, pois dispensam o feedback dos usuários finais sobre o produto.`, `Os pontos fracos do processo identificados na retrospectiva podem virar uma lista de tarefas para a melhoria contínua da organização.`, `As retrospectivas adotam cinco valores, incluindo coragem e respeito, cruciais para a melhoria contínua.`], answerIndex: 2, explanation: `O valor da <b>retrospectiva</b> é identificar o que funcionou e o que pode melhorar, gerando ações concretas para a <b>melhoria contínua do processo</b>. As demais opções são justificativas fracas ou incorretas.` },

  // ---- Capítulo 3 (Sample Exam A: Q15–Q18) ----
  { id: "c3-23", chapter: 3, prompt: `Qual das opções a seguir NÃO é um benefício dos testes estáticos?`, options: [`Ter um gerenciamento de defeitos MENOS dispendioso por detectar defeitos MAIS TARDE no SDLC.`, `Corrigir defeitos encontrados no teste estático costuma ser muito mais barato do que corrigir os do teste dinâmico.`, `Encontrar defeitos de codificação que poderiam não ser achados apenas com testes dinâmicos.`, `Detectar lacunas e inconsistências nos requisitos.`], answerIndex: 0, explanation: `O teste estático detecta defeitos <b>cedo</b> (não tarde) no ciclo, o que barateia a correção. A primeira opção inverte esse benefício, por isso NÃO é um benefício do teste estático.` },
  { id: "c3-24", chapter: 3, prompt: `Qual dos seguintes é um benefício do feedback antecipado e frequente?`, options: [`Melhora o processo de teste para projetos futuros.`, `Força os clientes a priorizarem seus requisitos com base nos riscos acordados.`, `É a única maneira de medir a qualidade das mudanças.`, `Ajuda a evitar mal-entendidos sobre os requisitos.`], answerIndex: 3, explanation: `O <b>feedback antecipado e frequente</b> permite alinhar entendimento cedo, <b>evitando mal-entendidos sobre os requisitos</b> e o retrabalho caro que eles causariam.` },
  { id: "c3-25", chapter: 3, prompt: `As revisões usadas na sua organização têm estes atributos: existe o papel de um redator; o objetivo principal é avaliar a qualidade; a reunião é conduzida pelo autor do produto de trabalho; há preparação individual; e é produzido um relatório de revisão. Qual tipo de revisão é o MAIS provável de estar sendo usado?`, options: [`Revisão informal.`, `Walkthrough.`, `Revisão técnica.`, `Inspeção.`], answerIndex: 2, explanation: `Preparação individual, foco em avaliar qualidade, papel de redator e relatório de revisão, com reunião conduzida pelo autor, caracterizam a <b>revisão técnica</b>. A inspeção seria conduzida por um moderador (não pelo autor) e a informal não produz relatório.` },
  { id: "c3-26", chapter: 3, prompt: `Qual destas afirmações NÃO é um fator que contribui para revisões bem-sucedidas?`, options: [`Os participantes devem dedicar tempo suficiente para a análise.`, `Dividir grandes produtos de trabalho em partes menores para reduzir o esforço por sessão.`, `Os participantes devem evitar comportamentos que indiquem tédio, exasperação ou hostilidade.`, `As FALHAS encontradas devem ser reconhecidas, apreciadas e tratadas de forma objetiva.`], answerIndex: 3, explanation: `Em revisões (teste estático) encontram-se <b>defeitos, não falhas</b> — falhas só ocorrem na execução dinâmica. Por isso a frase que fala em "falhas" descreve algo impossível na revisão e não é um fator de sucesso; o fator real é tratar os <b>defeitos</b> de forma objetiva.` },

  // ---- Capítulo 4 (Sample Exam A: Q19,Q20,Q24–Q29) ----
  { id: "c4-43", chapter: 4, prompt: `Qual das seguintes é uma característica das técnicas de teste baseadas em experiência?`, options: [`Os casos de teste são criados com base em informações detalhadas do projeto.`, `Os itens da seção de código da interface são usados para medir a cobertura.`, `As técnicas dependem muito do conhecimento do testador sobre o software e o domínio do negócio.`, `Os casos de teste são usados para identificar desvios dos requisitos.`], answerIndex: 2, explanation: `As técnicas <b>baseadas em experiência</b> (suposição de erro, exploratório, checklist) apoiam-se fortemente no <b>conhecimento e na experiência do testador</b> sobre o software e o domínio. As demais descrevem técnicas caixa-preta ou caixa-branca.` },
  { id: "c4-44", chapter: 4, prompt: `Você testa um formulário de busca de apartamento com dois critérios: andar (térreo, primeiro, segundo) e tipo de jardim (sem jardim, jardim pequeno, jardim grande). Só apartamentos no térreo podem ter jardim, e a validação impede combinações que violem essa regra. Cada teste informa andar e tipo de jardim. Qual é o número MÍNIMO de casos de teste para atingir 100% de cobertura de particionamento de equivalência?`, options: [`3`, `4`, `5`, `6`], answerIndex: 1, explanation: `São 3 partições de andar e 3 de jardim (6 partições no total). Como cada caso cobre um andar e um tipo de jardim ao mesmo tempo, bastam <b>4 casos</b> para cobrir todas as partições válidas, respeitando a regra de que jardins só existem no térreo.` },
  { id: "c4-45", chapter: 4, prompt: `Seu conjunto de testes atingiu 100% de cobertura de instrução (statement). Qual é a consequência desse fato?`, options: [`Cada instrução do código que contém um defeito foi executada pelo menos uma vez.`, `Qualquer conjunto com mais casos de teste que o seu também alcançará 100% de cobertura de instrução.`, `Cada caminho (path) no código foi executado pelo menos uma vez.`, `Cada combinação de valores de entrada foi testada pelo menos uma vez.`], answerIndex: 0, explanation: `100% de cobertura de instrução significa que <b>toda instrução executável foi executada</b> — logo, qualquer instrução com defeito também foi executada ao menos uma vez. Isso não garante cobertura de todos os caminhos nem de todas as combinações de entrada.` },
  { id: "c4-46", chapter: 4, prompt: `Qual das opções a seguir NÃO é verdadeira sobre o teste caixa-branca?`, options: [`Durante o teste caixa-branca, toda a implementação do software é considerada.`, `As métricas de cobertura caixa-branca podem ajudar a identificar testes adicionais para aumentar a cobertura do código.`, `As técnicas de teste caixa-branca podem ser usadas em testes estáticos.`, `O teste caixa-branca pode ajudar a identificar lacunas na implementação dos requisitos.`], answerIndex: 3, explanation: `O caixa-branca testa a <b>estrutura existente</b> do código; ele não revela um requisito que simplesmente não foi implementado (isso cabe ao caixa-preta). Por isso a 4ª afirmação é a que NÃO é verdadeira.` },
  { id: "c4-47", chapter: 4, prompt: `Qual das opções a seguir descreve MELHOR o conceito por trás da suposição de erros (error guessing)?`, options: [`Usar seu conhecimento e experiência sobre defeitos encontrados no passado e erros típicos cometidos por desenvolvedores.`, `Usar sua experiência pessoal de desenvolvimento e os erros que você cometeu como desenvolvedor.`, `Imaginar que você é o usuário do objeto de teste e adivinhar os erros que ele cometeria ao usá-lo.`, `Duplicar rapidamente a tarefa de desenvolvimento para identificar os erros que um desenvolvedor pode cometer.`], answerIndex: 0, explanation: `A <b>suposição de erros</b> usa o conhecimento e a experiência do testador sobre <b>defeitos passados e erros típicos de desenvolvedores</b> para antecipar onde o produto pode falhar.` },
  { id: "c4-48", chapter: 4, prompt: `Houve atraso no lançamento de um aplicativo totalmente novo e a execução dos testes começou tarde, mas você tem conhecimento de domínio detalhado e boas habilidades analíticas. A lista completa de requisitos ainda não foi compartilhada e a gerência já pede resultados de teste. Qual técnica se encaixa MELHOR?`, options: [`Testes baseados em listas de verificação.`, `Suposição de erros.`, `Testes exploratórios.`, `Teste de ramificação (branch).`], answerIndex: 2, explanation: `Sem requisitos completos, com pressão de tempo e um testador experiente no domínio, o <b>teste exploratório</b> é ideal: projeto e execução são simultâneos, aprendendo sobre o sistema e gerando resultados rapidamente.` },
  { id: "c4-49", chapter: 4, prompt: `Qual das opções a seguir descreve MELHOR como os critérios de aceite podem ser documentados?`, options: [`Realizar retrospectivas para determinar as necessidades reais dos stakeholders sobre uma história de usuário.`, `Usar o formato dado/quando/então para descrever uma condição de teste ligada a uma história de usuário.`, `Usar comunicação verbal para reduzir o risco de mal-entendidos sobre os critérios de aceite.`, `Documentar os riscos de uma história de usuário em um plano de teste para apoiar o teste baseado em risco.`], answerIndex: 1, explanation: `Uma forma comum de documentar critérios de aceite é o formato <b>dado/quando/então</b> (given/when/then), que descreve de maneira clara a condição, o gatilho e o resultado esperado.` },
  { id: "c4-50", chapter: 4, prompt: `Considere a história: "Como editor, quero revisar o conteúdo antes de publicá-lo, para garantir que a gramática esteja correta", com critérios de aceite: o usuário faz login como "Editor"; visualiza páginas existentes; edita o conteúdo; adiciona comentários de marcação; salva as alterações; pode reatribuir o papel de "proprietário do conteúdo". Qual é o MELHOR exemplo de teste ATDD para essa história?`, options: [`Testar se o editor pode salvar o documento após excluir o conteúdo da página.`, `Testar se o proprietário do conteúdo pode fazer login e atualizar o conteúdo.`, `Testar se o editor pode programar o conteúdo editado para publicação.`, `Testar se o editor pode reatribuir a outro editor para fazer atualizações.`], answerIndex: 0, explanation: `Um bom teste <b>ATDD</b> exercita um critério de aceite da história. Salvar após editar/excluir conteúdo testa diretamente o critério "salvar as alterações" no papel de editor. As demais opções envolvem papéis ou funções (agendar publicação, reatribuir a outro editor) que não estão nos critérios.` },

  // ---- Capítulo 5 (Sample Exam A: Q30,Q31,Q32,Q35,Q36,Q37) ----
  { id: "c5-36", chapter: 5, prompt: `Como os testadores agregam valor aos planejamentos de iteração e de lançamento?`, options: [`Os testadores determinam a prioridade das histórias de usuário a desenvolver.`, `Os testadores se concentram apenas nos aspectos funcionais do sistema.`, `Os testadores participam da identificação e da avaliação de riscos das histórias de usuário.`, `Os testadores garantem o lançamento de software de alta qualidade projetando testes cedo no planejamento.`], answerIndex: 2, explanation: `No planejamento de iteração e de lançamento, os testadores agregam valor sobretudo na <b>identificação e avaliação de riscos</b> das histórias, ajudando a priorizar e a estimar o esforço de teste.` },
  { id: "c5-37", chapter: 5, prompt: `Quais DUAS opções a seguir são critérios de SAÍDA para testar um sistema? (A) Prontidão do ambiente de teste; (B) A capacidade do testador de fazer login no objeto de teste; (C) A densidade de defeitos estimada foi atingida; (D) Os requisitos foram traduzidos para o formato dado/quando/então; (E) Os testes de regressão estão automatizados.`, options: [`A e E`, `B e A`, `C e E`, `C e A`, `B e C`], answerIndex: 2, explanation: `Critérios de <b>saída</b> definem quando parar/concluir os testes: atingir a <b>densidade de defeitos estimada</b> (C) e ter os <b>testes de regressão automatizados</b> (E). Prontidão do ambiente e login são critérios de entrada; traduzir requisitos é atividade de análise.` },
  { id: "c5-38", chapter: 5, prompt: `Sua equipe usa estimativa de três pontos para estimar o esforço de um recurso de alto risco: estimativa otimista = 2 h/h; mais provável = 11 h/h; pessimista = 14 h/h. Qual é a estimativa final?`, options: [`9 h/h`, `14 h/h`, `11 h/h`, `10 h/h`], answerIndex: 3, explanation: `Estimativa de três pontos (PERT): E = (otimista + 4 × mais provável + pessimista) / 6 = (2 + 44 + 14) / 6 = 60 / 6 = <b>10 h/h</b>.` },
  { id: "c5-39", chapter: 5, prompt: `Durante uma análise de risco, identificou-se: risco — o tempo de resposta é muito longo para gerar um relatório; probabilidade — média; impacto — alto. Resposta ao risco: (1) uma equipe de teste independente realiza testes de performance durante o teste do sistema; (2) uma amostra de usuários finais realiza testes de aceite alfa e beta antes do lançamento. Que medida foi proposta em resposta a esse risco?`, options: [`Aceitação do risco.`, `Plano de contingência.`, `Mitigação do risco.`, `Transferência do risco.`], answerIndex: 2, explanation: `Realizar testes de performance e de aceite para reduzir a probabilidade/impacto do risco antes do lançamento é uma medida de <b>mitigação de risco</b> — agir proativamente para diminuir o risco.` },
  { id: "c5-40", chapter: 5, prompt: `Qual ferramenta uma equipe ágil pode usar para mostrar quanto trabalho já foi concluído e quanto ainda resta em uma determinada iteração?`, options: [`Critérios de aceite.`, `Relatório de defeitos.`, `Relatório de conclusão do teste.`, `Gráfico de Burndown.`], answerIndex: 3, explanation: `O <b>gráfico de burndown</b> mostra visualmente o trabalho restante ao longo da iteração, comunicando o progresso da equipe em tempo real.` },
  { id: "c5-41", chapter: 5, prompt: `Você precisa atualizar um script de teste automatizado para atender a um novo requisito. Qual processo indica que você deve criar uma NOVA VERSÃO do script no repositório de testes?`, options: [`Gerenciamento de rastreabilidade.`, `Teste de manutenção.`, `Gerenciamento de configuração.`, `Engenharia de requisitos.`], answerIndex: 2, explanation: `Manter o versionamento e a integridade dos itens de teste (como criar uma nova versão do script no repositório) é papel do <b>gerenciamento de configuração</b>.` },

  // ---- Capítulo 6 (Sample Exam A: Q39,Q40) ----
  { id: "c6-12", chapter: 6, prompt: `Qual atividade de teste é suportada por uma ferramenta de preparação de dados de teste?`, options: [`Monitoramento e controle de testes.`, `Análise e projeto de testes.`, `Implementação e execução de testes.`, `Conclusão do teste.`], answerIndex: 2, explanation: `As ferramentas de <b>preparação de dados de teste</b> geram e gerenciam os dados usados nos testes, apoiando as atividades de <b>implementação e execução</b>.` },
  { id: "c6-13", chapter: 6, prompt: `Qual item identifica corretamente um risco potencial de realizar automação de testes?`, options: [`Ela pode introduzir regressões desconhecidas na produção.`, `O esforço para manter o material de teste pode não ser alocado adequadamente.`, `As ferramentas e o material de teste associado podem não ser suficientemente confiáveis.`, `Ela pode reduzir o tempo alocado para testes manuais.`], answerIndex: 1, explanation: `Um risco típico da <b>automação de testes</b> é subestimar o custo de <b>manutenção</b>: se o esforço para manter scripts e material de teste não for alocado, a automação se degrada e perde valor.` },

  // ================================================================
  // Questões adicionais — alinhadas aos objetivos de aprendizado do
  // syllabus CTFL v4.0. Originais (não reproduzem os exames-modelo).
  // ================================================================

  // ---------------- Capítulo 1 (adicionais) ----------------
  { id: "c1-43", chapter: 1, prompt: `Durante qual atividade de teste o relatório de conclusão de teste (test completion report) é normalmente produzido?`, options: [`Planejamento de teste`, `Monitoramento e controle de teste`, `Implementação de teste`, `Conclusão de teste`], answerIndex: 3, explanation: `Cada atividade de teste gera testware próprio. O <b>relatório de conclusão de teste</b> resume o que foi feito e os resultados, sendo produzido na atividade de <b>conclusão de teste</b> (test completion).` },
  { id: "c1-44", chapter: 1, prompt: `Qual é o principal benefício de manter a rastreabilidade (traceability) entre a base de teste e o testware?`, options: [`Garante que 100% dos defeitos serão encontrados`, `Permite avaliar a cobertura, analisar o impacto de mudanças e apoiar auditorias`, `Elimina a necessidade de testes de regressão`, `Substitui o plano de teste`], answerIndex: 1, explanation: `A <b>rastreabilidade</b> liga requisitos, condições, casos de teste e resultados. Isso permite <b>medir cobertura</b>, avaliar o <b>impacto de mudanças</b> na base de teste e fornecer evidências para auditoria e governança.` },
  { id: "c1-45", chapter: 1, prompt: `Qual atividade é tipicamente responsabilidade do papel de gerenciamento de teste (test management), e não do papel de teste (testing)?`, options: [`Projetar, implementar e executar casos de teste`, `Planejar as atividades de teste e escrever/atualizar o(s) plano(s) de teste`, `Configurar o ambiente de teste`, `Registrar os resultados e relatar defeitos`], answerIndex: 1, explanation: `O papel de <b>gerenciamento de teste</b> assume a responsabilidade global pelo processo: <b>planejar</b>, liderar e escrever/atualizar o(s) plano(s). Projetar, configurar ambiente e executar são tarefas do papel de <b>teste</b>.` },
  { id: "c1-46", chapter: 1, prompt: `Além do conhecimento técnico, quais habilidades genéricas são essenciais para um bom testador?`, options: [`Apenas domínio profundo de uma linguagem de programação`, `Pensamento crítico e analítico, atenção a detalhes e boa comunicação com os stakeholders`, `Capacidade de trabalhar isolado, sem contato com a equipe`, `Foco exclusivo em produzir documentação formal`], answerIndex: 1, explanation: `Testar exige <b>pensamento crítico e analítico</b>, atenção a detalhes e sobretudo <b>boa comunicação</b> — inclusive para relatar defeitos de forma construtiva. Conhecimento técnico sozinho não basta.` },
  { id: "c1-47", chapter: 1, prompt: `O que caracteriza a abordagem de "equipe inteira" (whole-team approach) para a qualidade?`, options: [`Somente os testadores são responsáveis pela qualidade`, `Qualquer membro com o conhecimento necessário pode realizar qualquer tarefa e todos são corresponsáveis pela qualidade`, `O gerente de teste concentra toda a responsabilidade`, `A qualidade cabe exclusivamente aos desenvolvedores`], answerIndex: 1, explanation: `Na abordagem de <b>equipe inteira</b>, a qualidade é responsabilidade de <b>todos</b>: qualquer pessoa com o conhecimento apropriado pode executar qualquer tarefa, e testadores colaboram de perto com desenvolvedores e representantes de negócio.` },
  { id: "c1-48", chapter: 1, prompt: `Qual afirmação sobre a independência de teste é CORRETA?`, options: [`Testes feitos pelo próprio autor do código encontram mais defeitos que os de um testador independente`, `Um grau maior de independência tende a encontrar tipos diferentes de defeitos, mas o autor pode corrigir defeitos com baixo custo ao testar o próprio trabalho`, `Independência total é sempre obrigatória em qualquer projeto`, `A independência elimina completamente o viés de confirmação`], answerIndex: 1, explanation: `Há graus de <b>independência</b>. Maior independência costuma revelar defeitos <b>diferentes</b> (menos viés de confirmação), mas testar o próprio trabalho ainda tem valor: o autor encontra e corrige defeitos rapidamente e a baixo custo. Nenhum grau elimina totalmente o viés.` },
  { id: "c1-49", chapter: 1, prompt: `Uma equipe executa o mesmo conjunto de testes de regressão há vários ciclos e ele deixou de encontrar defeitos novos. Qual princípio explica isso e o que fazer?`, options: [`Ausência de erros — o software está pronto para produção`, `Paradoxo do pesticida — revisar e atualizar os testes existentes e criar novos casos`, `Agrupamento de defeitos — parar imediatamente de testar`, `Teste exaustivo — reduzir a suíte pela metade`], answerIndex: 1, explanation: `Pelo <b>paradoxo do pesticida</b>, repetir sempre os mesmos testes faz com que eles parem de encontrar defeitos novos. A resposta é <b>revisar e atualizar</b> os testes e <b>criar novos</b> para exercitar outras partes do software.` },
  { id: "c1-50", chapter: 1, prompt: `O princípio do agrupamento de defeitos (defect clustering) afirma que:`, options: [`Os defeitos se distribuem uniformemente por todo o sistema`, `Um pequeno número de módulos costuma concentrar a maioria dos defeitos`, `Todo módulo contém exatamente o mesmo número de defeitos`, `Defeitos nunca se concentram em áreas específicas`], answerIndex: 1, explanation: `O <b>agrupamento de defeitos</b> observa que poucos módulos tendem a concentrar a maior parte dos defeitos. Isso sustenta o teste baseado em risco: focar esforço onde os defeitos provavelmente estão.` },

  // ---------------- Capítulo 2 (adicionais) ----------------
  { id: "c2-30", chapter: 2, prompt: `No Test-Driven Development (TDD), qual é a ordem correta das etapas?`, options: [`Escrever o código e, depois, escrever os testes`, `Escrever um teste que falha, escrever código para fazê-lo passar e, então, refatorar`, `Escrever todos os testes de aceite antes de qualquer linha de código`, `Testar apenas ao final da iteração`], answerIndex: 1, explanation: `O ciclo do <b>TDD</b> é: escrever um <b>teste que falha</b> → escrever o <b>código mínimo</b> para passar → <b>refatorar</b> (red-green-refactor). Os testes guiam o design do código.` },
  { id: "c2-31", chapter: 2, prompt: `Qual abordagem "test-first" foca em expressar o comportamento desejado do sistema em linguagem simples e compreensível por todos os stakeholders, geralmente no formato dado/quando/então?`, options: [`TDD (Test-Driven Development)`, `BDD (Behavior-Driven Development)`, `Gerenciamento de configuração`, `Teste exploratório`], answerIndex: 1, explanation: `O <b>BDD</b> descreve o <b>comportamento</b> desejado em linguagem natural simples (dado/quando/então), aproximando negócio, desenvolvimento e teste. O TDD foca no design do código via testes; os demais nem são abordagens test-first.` },
  { id: "c2-32", chapter: 2, prompt: `Qual é um benefício da abordagem "shift-left" em teste?`, options: [`Adiar os testes para depois da entrega`, `Detectar e corrigir defeitos mais cedo, quando são mais baratos de resolver`, `Eliminar a necessidade de testes de aceite`, `Transferir toda a responsabilidade de teste para a equipe de operações`], answerIndex: 1, explanation: `<b>Shift-left</b> significa testar (e revisar) o mais cedo possível no ciclo. Encontrar defeitos cedo os torna <b>mais baratos</b> de corrigir — alinhado ao princípio do teste antecipado.` },
  { id: "c2-33", chapter: 2, prompt: `Qual nível de teste tem como objetivo principal verificar se componentes ou sistemas integrados funcionam em conjunto, com foco nas interfaces e interações?`, options: [`Teste de componente (unidade)`, `Teste de integração`, `Teste de sistema`, `Teste de aceite`], answerIndex: 1, explanation: `O <b>teste de integração</b> foca nas <b>interfaces e interações</b> entre componentes (integração de componentes) ou entre sistemas (integração de sistemas). O de componente isola uma unidade; o de sistema avalia o todo.` },
  { id: "c2-34", chapter: 2, prompt: `Avaliar quão bem o sistema se comporta sob determinada carga — tempo de resposta e uso de recursos — é um exemplo de qual tipo de teste?`, options: [`Teste funcional`, `Teste não funcional`, `Teste de confirmação`, `Teste caixa-branca`], answerIndex: 1, explanation: `Medir desempenho, tempo de resposta e uso de recursos avalia <b>como</b> o sistema se comporta, e não <b>o que</b> ele faz — é <b>teste não funcional</b> (neste caso, de desempenho/performance).` },
  { id: "c2-35", chapter: 2, prompt: `Qual das opções é um gatilho típico para o teste de manutenção?`, options: [`A redação de um novo plano de teste`, `Uma modificação, como uma correção, uma melhoria ou uma migração/atualização de ambiente`, `A criação de uma nova história de usuário`, `A realização de uma retrospectiva de iteração`], answerIndex: 1, explanation: `O <b>teste de manutenção</b> é disparado por <b>mudanças</b> em um sistema em operação: correções, melhorias, atualização/migração de ambiente ou aposentadoria do sistema. Ele inclui testar a mudança e regressão do que já existia.` },

  // ---------------- Capítulo 3 (adicionais) ----------------
  { id: "c3-27", chapter: 3, prompt: `Qual afirmação sobre o teste estático é CORRETA?`, options: [`Só pode ser aplicado a código-fonte`, `Pode ser aplicado a praticamente qualquer produto de trabalho que possa ser lido e compreendido (requisitos, contratos, modelos, código)`, `Exige a execução do software`, `Encontra falhas em tempo de execução`], answerIndex: 1, explanation: `O <b>teste estático</b> examina produtos de trabalho <b>sem executá-los</b>. Aplica-se a qualquer artefato legível: requisitos, histórias, contratos, modelos, código, etc. Ele encontra <b>defeitos</b> diretamente, não falhas.` },
  { id: "c3-28", chapter: 3, prompt: `Qual é um benefício do teste estático em comparação ao teste dinâmico?`, options: [`Encontra falhas em tempo de execução`, `Detecta defeitos cedo, antes de qualquer execução, reduzindo o custo de correção`, `Mede o desempenho do sistema sob carga`, `Valida a experiência real do usuário final`], answerIndex: 1, explanation: `O <b>teste estático</b> permite encontrar defeitos <b>antes da execução</b> — muitas vezes antes mesmo de existir código executável — o que torna a correção mais barata e evita que o defeito se propague.` },
  { id: "c3-29", chapter: 3, prompt: `Qual tipo de problema é MAIS facilmente encontrado por teste estático do que por teste dinâmico?`, options: [`Vazamentos de memória em tempo de execução`, `Requisitos ambíguos ou contraditórios e código morto (não alcançável)`, `Degradação de desempenho sob alta carga`, `Falhas de integração observáveis só em execução`], answerIndex: 1, explanation: `Certos defeitos são difíceis (ou impossíveis) de revelar dinamicamente: <b>ambiguidades e contradições em requisitos</b>, desvios de padrão e <b>código morto</b>. O teste estático os expõe por análise/revisão, sem executar.` },
  { id: "c3-30", chapter: 3, prompt: `Na sequência do processo de revisão, em qual atividade cada revisor examina individualmente o produto de trabalho para identificar possíveis anomalias?`, options: [`Planejamento`, `Revisão individual (exame individual)`, `Comunicação e análise das anomalias`, `Correção e relato`], answerIndex: 1, explanation: `O processo de revisão do v4.0 tem: planejamento, início da revisão, <b>revisão individual</b>, comunicação e análise das anomalias, e correção/relato. É na <b>revisão individual</b> que cada revisor examina o artefato e registra possíveis anomalias.` },
  { id: "c3-31", chapter: 3, prompt: `Em uma revisão, qual papel é responsável por conduzir a reunião e assegurar que ela ocorra de forma eficaz e ordenada?`, options: [`Autor`, `Gerente`, `Facilitador (moderador)`, `Escriba (redator)`], answerIndex: 2, explanation: `O <b>facilitador</b> (moderador) conduz a reunião, mantém a ordem e garante um ambiente seguro para a discussão. O autor é dono do artefato, o escriba registra as anomalias e o gerente decide sobre recursos.` },

  // ---------------- Capítulo 4 (adicionais) ----------------
  { id: "c4-51", chapter: 4, prompt: `Um campo aceita idades de 18 a 65 (inclusive). Quantas partições de equivalência existem para esse campo, considerando válidas e inválidas?`, options: [`1`, `2`, `3`, `4`], answerIndex: 2, explanation: `São <b>3 partições</b>: uma válida (18–65) e duas inválidas (menor que 18 e maior que 65). No particionamento de equivalência, testa-se um valor representativo de cada partição.` },
  { id: "c4-52", chapter: 4, prompt: `Para um campo que aceita inteiros de 1 a 100, quais valores a análise de valor limite de 2 valores (2-value BVA) manda testar?`, options: [`Apenas 1 e 100`, `0, 1, 100 e 101`, `1, 50 e 100`, `Apenas 0 e 101`], answerIndex: 1, explanation: `Na <b>BVA de 2 valores</b>, testam-se o valor no limite e o valor imediatamente <b>fora</b> dele. Para 1–100: <b>0 e 1</b> (limite inferior) e <b>100 e 101</b> (limite superior).` },
  { id: "c4-53", chapter: 4, prompt: `Qual é a principal vantagem do teste por tabela de decisão?`, options: [`Cobrir todos os caminhos possíveis do código`, `Testar de forma sistemática combinações de condições e as ações resultantes`, `Medir a cobertura de instrução`, `Dispensar a especificação de requisitos`], answerIndex: 1, explanation: `A <b>tabela de decisão</b> modela regras de negócio combinando <b>condições</b> e <b>ações</b>, garantindo que combinações relevantes de condições sejam testadas de forma sistemática — útil quando o comportamento depende de várias entradas.` },
  { id: "c4-54", chapter: 4, prompt: `O teste de transição de estados é MAIS adequado para testar:`, options: [`Cálculos matemáticos isolados`, `Sistemas cujo comportamento depende do estado atual e de eventos que provocam transições`, `A aparência visual da interface`, `O desempenho sob carga elevada`], answerIndex: 1, explanation: `O <b>teste de transição de estados</b> modela estados, eventos, transições e ações. É ideal para sistemas <b>dependentes de estado</b> (ex.: um caixa eletrônico, um pedido que muda de status), verificando transições válidas e inválidas.` },
  { id: "c4-55", chapter: 4, prompt: `Um conjunto de testes executou 30 das 40 instruções executáveis de um módulo. Qual é a cobertura de instrução (statement coverage)?`, options: [`40%`, `75%`, `133%`, `30%`], answerIndex: 1, explanation: `Cobertura de instrução = instruções executadas ÷ total de instruções executáveis = 30 ÷ 40 = <b>75%</b>.` },
  { id: "c4-56", chapter: 4, prompt: `O que a cobertura de ramo (branch coverage) de 100% assegura e a cobertura de instrução de 100% não assegura?`, options: [`Que todas as combinações de entrada foram testadas`, `Que toda decisão foi avaliada como verdadeira e falsa pelo menos uma vez`, `Que todos os caminhos do código foram testados`, `Que o código está livre de defeitos`], answerIndex: 1, explanation: `A <b>cobertura de ramo</b> exige que cada decisão assuma os resultados <b>verdadeiro e falso</b> ao menos uma vez — mais forte que a de instrução. 100% de ramo implica 100% de instrução, mas não garante todos os caminhos nem ausência de defeitos.` },
  { id: "c4-57", chapter: 4, prompt: `Qual é um benefício do teste caixa-branca?`, options: [`Pode revelar código não exercido por nenhum teste caixa-preta, como código morto ou funcionalidade oculta`, `Garante que o software está livre de defeitos`, `Dispensa qualquer conhecimento do código`, `Testa requisitos que não foram implementados`], answerIndex: 0, explanation: `Como se baseia na estrutura do código, o <b>caixa-branca</b> pode expor <b>código morto</b> ou <b>funcionalidade oculta</b> que os testes caixa-preta jamais exercitariam. Ele não revela, porém, requisitos ausentes na implementação.` },
  { id: "c4-58", chapter: 4, prompt: `Nos testes exploratórios, o que é comumente usado para organizar e guiar as sessões?`, options: [`Uma tabela de decisão`, `Um test charter (carta de teste) definindo objetivo, escopo e tempo da sessão`, `Um diagrama de transição de estados`, `Uma matriz de rastreabilidade de requisitos`], answerIndex: 1, explanation: `Os testes exploratórios costumam ser estruturados em <b>sessões guiadas por um test charter</b>, que define missão/objetivo, escopo e duração — frequentemente no formato de teste baseado em sessões (session-based testing).` },
  { id: "c4-59", chapter: 4, prompt: `Qual técnica baseada em experiência se apoia em uma lista de itens a verificar, derivada da experiência e do que é importante para o usuário?`, options: [`Suposição de erros`, `Teste exploratório`, `Teste baseado em lista de verificação (checklist)`, `Análise de valor limite`], answerIndex: 2, explanation: `O <b>teste baseado em checklist</b> usa uma lista de itens/condições a verificar, criada a partir da experiência e da relevância para o usuário. É uma técnica <b>baseada em experiência</b>, como a suposição de erros e o exploratório.` },
  { id: "c4-60", chapter: 4, prompt: `Segundo o modelo dos "3 Cs", quais são os três elementos de uma boa história de usuário?`, options: [`Custo, Contrato e Cronograma`, `Cartão, Conversa e Confirmação (Card, Conversation, Confirmation)`, `Cliente, Código e Cobertura`, `Condição, Critério e Caso`], answerIndex: 1, explanation: `Os <b>3 Cs</b> de uma boa história de usuário são: <b>Cartão</b> (Card — a descrição sucinta), <b>Conversa</b> (Conversation — o diálogo que esclarece a necessidade) e <b>Confirmação</b> (Confirmation — os critérios de aceite).` },
  { id: "c4-61", chapter: 4, prompt: `Qual é o propósito dos critérios de aceite de uma história de usuário?`, options: [`Definir os detalhes de implementação do código`, `Definir as condições que o software deve satisfazer para ser aceito pelos stakeholders`, `Substituir o plano de teste`, `Medir a cobertura de código`], answerIndex: 1, explanation: `Os <b>critérios de aceite</b> descrevem as condições que uma história deve cumprir para ser considerada pronta e <b>aceita</b>. Servem de base para os testes de aceite (e para o ATDD).` },
  { id: "c4-62", chapter: 4, prompt: `No ATDD (Acceptance Test-Driven Development), quando os testes de aceite são criados?`, options: [`Após a entrega do software ao usuário`, `A partir dos critérios de aceite, de forma colaborativa, antes de o desenvolvimento começar`, `Apenas pela equipe de teste, ao final da iteração`, `Somente durante o teste de manutenção`], answerIndex: 1, explanation: `No <b>ATDD</b>, a equipe deriva os testes de aceite <b>colaborativamente a partir dos critérios de aceite</b>, <b>antes</b> de codificar. Esses testes guiam o desenvolvimento e confirmam que a história foi atendida.` },

  // ---------------- Capítulo 5 (adicionais) ----------------
  { id: "c5-42", chapter: 5, prompt: `Qual das opções descreve MELHOR o propósito de um plano de teste?`, options: [`Registrar todos os defeitos encontrados durante a execução`, `Documentar objetivos, recursos e processos de teste e servir como meio de comunicação com os stakeholders`, `Listar apenas os casos de teste automatizados`, `Medir a cobertura de código atingida`], answerIndex: 1, explanation: `O <b>plano de teste</b> descreve objetivos, escopo, abordagem, recursos, cronograma e critérios das atividades de teste. Além de guiar a equipe, é um importante <b>meio de comunicação</b> com os stakeholders.` },
  { id: "c5-43", chapter: 5, prompt: `Qual é um exemplo típico de critério de ENTRADA para iniciar a execução dos testes?`, options: [`Todos os defeitos críticos já foram corrigidos`, `O ambiente de teste está pronto e a base de teste está disponível e suficientemente estável`, `A cobertura de código atingiu 100%`, `O relatório de conclusão de teste foi assinado`], answerIndex: 1, explanation: `Critérios de <b>entrada</b> definem o que deve estar pronto para <b>começar</b> uma atividade: por exemplo, <b>ambiente de teste pronto</b> e base de teste disponível/estável. Corrigir defeitos críticos e concluir relatórios são critérios de saída.` },
  { id: "c5-44", chapter: 5, prompt: `Qual técnica de estimativa de esforço de teste se baseia no julgamento de especialistas, que estimam individualmente e depois discutem até convergir?`, options: [`Estimativa baseada em métricas (dados históricos)`, `Wideband Delphi (baseada em especialistas)`, `Estimativa de três pontos`, `Gráfico de burndown`], answerIndex: 1, explanation: `O <b>Wideband Delphi</b> é uma técnica <b>baseada em especialistas</b>: cada um estima individualmente e o grupo discute em rodadas até convergir (o Planning Poker é uma variante ágil). A estimativa por métricas usa dados históricos.` },
  { id: "c5-45", chapter: 5, prompt: `Qual estratégia de priorização de casos de teste executa primeiro os testes que cobrem as funcionalidades de maior risco?`, options: [`Priorização por cobertura`, `Priorização baseada em risco`, `Priorização baseada em requisitos`, `Priorização por ordem de escrita`], answerIndex: 1, explanation: `Na <b>priorização baseada em risco</b>, os testes das áreas de <b>maior risco</b> rodam primeiro, de modo que os problemas mais importantes sejam encontrados cedo. Também existem priorizações por cobertura e por requisitos.` },
  { id: "c5-46", chapter: 5, prompt: `O que a pirâmide de testes (test pyramid) ilustra?`, options: [`Que se deve ter mais testes de UI ponta a ponta do que de unidade`, `Que a maioria dos testes deve estar nos níveis mais baixos (unidade/componente), com menos testes nos níveis mais altos (UI/ponta a ponta)`, `Que todos os níveis devem ter a mesma quantidade de testes`, `A ordem cronológica de execução dos testes`], answerIndex: 1, explanation: `A <b>pirâmide de testes</b> recomenda muitos testes rápidos e baratos nos <b>níveis baixos</b> (unidade/componente) e poucos testes lentos e caros no topo (UI/ponta a ponta), equilibrando velocidade de feedback e custo de manutenção.` },
  { id: "c5-47", chapter: 5, prompt: `Para que servem os quadrantes de teste (Testing Quadrants)?`, options: [`Medir a cobertura de código`, `Classificar e equilibrar os tipos de teste conforme o foco (negócio ou tecnologia) e o propósito (apoiar a equipe ou avaliar o produto)`, `Priorizar defeitos por severidade`, `Estimar o esforço de teste`], answerIndex: 1, explanation: `Os <b>quadrantes de teste</b> ajudam a equipe a <b>classificar e equilibrar</b> os tipos de teste em dois eixos: voltados ao <b>negócio</b> ou à <b>tecnologia</b>, e destinados a <b>apoiar a equipe</b> ou a <b>avaliar/criticar o produto</b>.` },
  { id: "c5-48", chapter: 5, prompt: `"O fornecedor pode não entregar o ambiente de teste no prazo" é um exemplo de qual tipo de risco?`, options: [`Risco de produto`, `Risco de projeto`, `Risco de qualidade do software`, `Risco técnico de implementação`], answerIndex: 1, explanation: `<b>Riscos de projeto</b> afetam a capacidade de o projeto atingir seus objetivos (prazos, recursos, fornecedores, equipe). Um atraso de fornecedor é um risco de projeto. Já os <b>riscos de produto</b> referem-se a possíveis defeitos/qualidade do próprio software.` },
  { id: "c5-49", chapter: 5, prompt: `O nível de um risco é determinado pela combinação de quais dois fatores?`, options: [`Custo e tempo`, `Probabilidade (likelihood) de ocorrência e impacto (dano) caso ocorra`, `Severidade e prioridade do defeito`, `Cobertura e densidade de defeitos`], answerIndex: 1, explanation: `O <b>nível de risco</b> resulta da combinação da <b>probabilidade</b> de o risco se concretizar com o <b>impacto</b> (dano) que causaria — quanto maiores ambos, maior o risco.` },
  { id: "c5-50", chapter: 5, prompt: `Qual das opções é uma métrica de cobertura de teste?`, options: [`Número total de defeitos encontrados`, `Porcentagem de requisitos ou de código exercitados pelos testes`, `Horas trabalhadas pela equipe de teste`, `Número de testadores no projeto`], answerIndex: 1, explanation: `Métricas de <b>cobertura</b> medem a proporção da base de teste exercitada — por exemplo, <b>% de requisitos</b> ou de <b>código</b> coberto pelos testes. Contagem de defeitos e horas são outros tipos de métrica.` },
  { id: "c5-51", chapter: 5, prompt: `Segundo as boas práticas de gerenciamento de defeitos, um bom relatório de defeito deve incluir, entre outros itens:`, options: [`Apenas o nome de quem encontrou o defeito`, `Identificação, descrição, passos para reproduzir, severidade e prioridade`, `Somente a severidade do defeito`, `O trecho de código-fonte já corrigido`], answerIndex: 1, explanation: `Um <b>relatório de defeito</b> útil traz identificação, descrição clara, <b>passos para reproduzir</b>, resultado esperado x obtido, além de <b>severidade</b> e <b>prioridade</b> — informação suficiente para reproduzir, avaliar e tratar o problema.` },

  // ---------------- Capítulo 6 (adicionais) ----------------
  { id: "c6-14", chapter: 6, prompt: `Uma ferramenta de gerenciamento de teste (test management tool) apoia principalmente:`, options: [`A execução automática de scripts de interface de usuário`, `A organização e o rastreamento de artefatos de teste — casos, execuções e defeitos — com rastreabilidade à base de teste`, `A análise estática do código-fonte`, `A geração de massa de dados de teste`], answerIndex: 1, explanation: `As <b>ferramentas de gerenciamento de teste</b> organizam e rastreiam casos de teste, execuções e defeitos, mantendo <b>rastreabilidade</b> com requisitos e produzindo relatórios de progresso.` },
  { id: "c6-15", chapter: 6, prompt: `Qual é um benefício típico da automação de testes?`, options: [`Eliminar completamente a necessidade de testadores`, `Reduzir o esforço repetitivo de execução, permitindo rodar testes com mais frequência e consistência (ex.: regressão)`, `Garantir a ausência total de defeitos`, `Substituir o teste exploratório`], answerIndex: 1, explanation: `A <b>automação</b> reduz o esforço manual repetitivo e permite executar testes de forma <b>frequente, rápida e consistente</b> — especialmente valiosa para regressão. Ela não substitui pessoas nem o teste exploratório, e não garante ausência de defeitos.` },
  { id: "c6-16", chapter: 6, prompt: `As ferramentas de análise estática (static analysis tools) ajudam os desenvolvedores a:`, options: [`Medir o tempo de resposta do sistema sob carga`, `Identificar defeitos no código-fonte sem executá-lo, como violações de padrões e trechos suspeitos`, `Gerenciar o repositório de casos de teste`, `Registrar sessões de teste exploratório`], answerIndex: 1, explanation: `As <b>ferramentas de análise estática</b> examinam o <b>código sem executá-lo</b>, apontando violações de padrões de codificação, código suspeito e possíveis defeitos — apoiando o teste estático.` },
];
